const book: BibleBook = {
  id: 'revelation',
  name: 'Apocalipse',
  englishName: 'Revelation',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'This is the Revelation of Jesus Christ, which God gave him to show to his servants the things which must happen soon, which he sent and made known by his angel to his servant, John,', pt: 'Revelação de Jesus Cristo, que Deus lhe deu para mostrar aos seus servos as coisas que brevemente devem acontecer; e, enviando-as pelo seu anjo, as notificou a seu servo João;' },
      { v: 2, en: 'who testified to God’s word, and of the testimony of Jesus Christ, about everything that he saw.', pt: 'o qual testificou da palavra de Deus, e do testemunho de Jesus Cristo, de tudo quanto viu.' },
      { v: 3, en: 'Blessed is he who reads and those who hear the words of the prophecy, and keep the things that are written in it, for the time is at hand.', pt: 'Bem-aventurado aquele que lê e bem-aventurados os que ouvem as palavras desta profecia e guardam as coisas que nela estão escritas; porque o tempo está próximo.' },
      { v: 4, en: 'John, to the seven assemblies that are in Asia: Grace to you and peace, from God, who is and who was and who is to come; and from the seven Spirits who are before his throne;', pt: 'João, às sete igrejas que estão na Ásia: Graça a vós e paz da parte daquele que é, e que era, e que há de vir, e da dos sete espíritos que estão diante do seu trono;' },
      { v: 5, en: 'and from Jesus Christ, the faithful witness, the firstborn of the dead, and the ruler of the kings of the earth. To him who loves us, and washed us from our sins by his blood;', pt: 'e da parte de Jesus Cristo, que é a fiel testemunha, o primogênito dos mortos e o Príncipe dos reis da terra. Âquele que nos ama, e pelo seu sangue nos libertou dos nossos pecados,' },
      { v: 6, en: 'and he made us to be a Kingdom, priests to his God and Father; to him be the glory and the dominion forever and ever. Amen.', pt: 'e nos fez reino, sacerdotes para Deus, seu Pai, a ele seja glória e domínio pelos séculos dos séculos. Amém.' },
      { v: 7, en: 'Behold, he is coming with the clouds, and every eye will see him, including those who pierced him. All the tribes of the earth will mourn over him. Even so, Amen.', pt: 'Eis que vem com as nuvens, e todo olho o verá, até mesmo aqueles que o traspassaram; e todas as tribos da terra se lamentarão sobre ele. Sim. Amém.' },
      { v: 8, en: '“I am the Alpha and the Omega, ” says the Lord God, “who is and who was and who is to come, the Almighty.”', pt: 'Eu sou o Alfa e o èmega, diz o Senhor Deus, aquele que é, e que era, e que há de vir, o Todo-Poderoso.' },
      { v: 9, en: 'I John, your brother and partner with you in the oppression, Kingdom, and perseverance in Christ Jesus, was on the isle that is called Patmos because of God’s Word and the testimony of Jesus Christ.', pt: 'Eu, João, irmão vosso e companheiro convosco na aflição, no reino, e na perseverança em Jesus, estava na ilha chamada Patmos por causa da palavra de Deus e do testemunho de Jesus.' },
      { v: 10, en: 'I was in the Spirit on the Lord’s day, and I heard behind me a loud voice, like a trumpet', pt: 'Eu fui arrebatado em espírito no dia do Senhor, e ouvi por detrás de mim uma grande voz, como de trombeta,' },
      { v: 11, en: 'saying, “What you see, write in a book and send to the seven assemblies: to Ephesus, Smyrna, Pergamum, Thyatira, Sardis, Philadelphia, and to Laodicea.”', pt: 'que dizia: O que vês, escreve-o num livro, e envia-o às sete igrejas: a Éfeso, a Esmirna, a Pérgamo, a Tiatira, a Sardes, a Filadélfia e a Laodicéia.' },
      { v: 12, en: 'I turned to see the voice that spoke with me. Having turned, I saw seven golden lamp stands.', pt: 'E voltei-me para ver quem falava comigo. E, ao voltar-me, vi sete candeeiros de ouro,' },
      { v: 13, en: 'And among the lamp stands was one like a son of man, clothed with a robe reaching down to his feet, and with a golden sash around his chest.', pt: 'e no meio dos candeeiros um semelhante a filho de homem, vestido de uma roupa talar, e cingido à altura do peito com um cinto de ouro;' },
      { v: 14, en: 'His head and his hair were white as white wool, like snow. His eyes were like a flame of fire.', pt: 'e a sua cabeça e cabelos eram brancos como lã branca, como a neve; e os seus olhos como chama de fogo;' },
      { v: 15, en: 'His feet were like burnished brass, as if it had been refined in a furnace. His voice was like the voice of many waters.', pt: 'e os seus pés, semelhantes a latão reluzente que fora refinado numa fornalha; e a sua voz como a voz de muitas águas.' },
      { v: 16, en: 'He had seven stars in his right hand. Out of his mouth proceeded a sharp two-edged sword. His face was like the sun shining at its brightest.', pt: 'Tinha ele na sua destra sete estrelas; e da sua boca saía uma aguda espada de dois gumes; e o seu rosto era como o sol, quando resplandece na sua força.' },
      { v: 17, en: 'When I saw him, I fell at his feet like a dead man. He laid his right hand on me, saying, “Don’t be afraid. I am the first and the last,', pt: 'Quando o vi, caí a seus pés como morto; e ele pôs sobre mim a sua destra, dizendo: Não temas; eu sou o primeiro e o último,' },
      { v: 18, en: 'and the Living one. I was dead, and behold, I am alive forever and ever. Amen. I have the keys of Death and of Hades.', pt: 'e o que vivo; fui morto, mas eis aqui estou vivo pelos séculos dos séculos; e tenho as chaves da morte e do hades.' },
      { v: 19, en: 'Write therefore the things which you have seen, and the things which are, and the things which will happen hereafter;', pt: 'escreve, pois, as coisas que tens visto, e as que são, e as que depois destas hão de suceder.' },
      { v: 20, en: 'the mystery of the seven stars which you saw in my right hand, and the seven golden lamp stands. The seven stars are the angels of the seven assemblies. The seven lamp stands are seven assemblies.', pt: 'Eis o mistério das sete estrelas, que viste na minha destra, e dos sete candeeiros de ouro: as estrelas são os anjos das sete igrejas, e os sete candeeiros são as sete igrejas.' },
    ],
    2: [
      { v: 1, en: '“To the angel of the assembly in Ephesus write: “He who holds the seven stars in his right hand, he who walks among the seven golden lamp stands says these things:', pt: 'Ao anjo da igreja em Éfeso escreve: Isto diz aquele que tem na sua destra as sete estrelas, que anda no meio dos sete candeeiros de ouro:' },
      { v: 2, en: '“I know your works, and your toil and perseverance, and that you can’t tolerate evil men, and have tested those who call themselves apostles, and they are not, and found them false.', pt: 'Conheço as tuas obras, e o teu trabalho, e a tua perseverança; sei que não podes suportar os maus, e que puseste à prova os que se dizem apóstolos e não o são, e os achaste mentirosos;' },
      { v: 3, en: 'You have perseverance and have endured for my name’s sake, and have not grown weary.', pt: 'e tens perseverança e por amor do meu nome sofreste, e não desfaleceste.' },
      { v: 4, en: 'But I have this against you, that you left your first love.', pt: 'Tenho, porém, contra ti que deixaste o teu primeiro amor.' },
      { v: 5, en: 'Remember therefore from where you have fallen, and repent and do the first works; or else I am coming to you swiftly, and will move your lamp stand out of its place, unless you repent.', pt: 'Lembra-te, pois, donde caíste, e arrepende-te, e pratica as primeiras obras; e se não, brevemente virei a ti, e removerei do seu lugar o teu candeeiro, se não te arrependeres.' },
      { v: 6, en: 'But this you have, that you hate the works of the Nicolaitans, which I also hate.', pt: 'Tens, porém, isto, que aborreces as obras dos nicolaítas, as quais eu também aborreço.' },
      { v: 7, en: 'He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes I will give to eat from the tree of life, which is in the Paradise of my God.', pt: 'Quem tem ouvidos, ouça o que o Espírito diz às igrejas. Ao que vencer, dar-lhe-ei a comer da árvore da vida, que está no paraíso de Deus.' },
      { v: 8, en: '“To the angel of the assembly in Smyrna write: “The first and the last, who was dead, and has come to life says these things:', pt: 'Ao anjo da igreja em Esmirna escreve: Isto diz o primeiro e o último, que foi morto e reviveu:' },
      { v: 9, en: '“I know your works, oppression, and your poverty (but you are rich), and the blasphemy of those who say they are Jews, and they are not, but are a synagogue of Satan.', pt: 'Conheço a tua tribulação e a tua pobreza (mas tu és rico), e a blasfêmia dos que dizem ser judeus, e não o são, porém são sinagoga de Satanás.' },
      { v: 10, en: 'Don’t be afraid of the things which you are about to suffer. Behold, the devil is about to throw some of you into prison, that you may be tested; and you will have oppression for ten days. Be faithful to death, and I will give you the crown of life.', pt: 'Não temas o que hás de padecer. Eis que o Diabo está para lançar alguns de vós na prisão, para que sejais provados; e tereis uma tribulação de dez dias. Sê fiel até a morte, e dar-te-ei a coroa da vida.' },
      { v: 11, en: 'He who has an ear, let him hear what the Spirit says to the assemblies. He who overcomes won’t be harmed by the second death.', pt: 'Quem tem ouvidos, ouça o que o Espírito diz às igrejas. O que vencer, de modo algum sofrerá o dado da segunda morte.' },
      { v: 12, en: '“To the angel of the assembly in Pergamum write: “He who has the sharp two-edged sword says these things:', pt: 'Ao anjo da igreja em Pérgamo escreve: Isto diz aquele que tem a espada aguda de dois gumes:' },
      { v: 13, en: '“I know your works and where you dwell, where Satan’s throne is. You hold firmly to my name, and didn’t deny my faith in the days of Antipas my witness, my faithful one, who was killed among you, where Satan dwells.', pt: 'Sei onde habitas, que é onde está o trono de Satanás; mas reténs o meu nome e não negaste a minha fé, mesmo nos dias de Antipas, minha fiel testemunha, o qual foi morto entre vós, onde Satanás habita.' },
      { v: 14, en: 'But I have a few things against you, because you have there some who hold the teaching of Balaam, who taught Balak to throw a stumbling block before the children of Israel, to eat things sacrificed to idols, and to commit sexual immorality.', pt: 'entretanto, algumas coisas tenho contra ti; porque tens aí os que seguem a doutrina de Balaão, o qual ensinava Balaque a lançar tropeços diante dos filhos de Israel, introduzindo-os a comerem das coisas sacrificadas a ídolos e a se prostituírem.' },
      { v: 15, en: 'So you also have some who hold to the teaching of the Nicolaitans likewise.', pt: 'Assim tens também alguns que de igual modo seguem a doutrina dos nicolaítas.' },
      { v: 16, en: 'Repent therefore, or else I am coming to you quickly, and I will make war against them with the sword of my mouth.', pt: 'Arrepende-te, pois; ou se não, virei a ti em breve, e contra eles batalharei com a espada da minha boca.' },
      { v: 17, en: 'He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes, to him I will give of the hidden manna, and I will give him a white stone, and on the stone a new name written, which no one knows but he who receives it.', pt: 'Quem tem ouvidos, ouça o que o Espírito diz às igrejas. Ao que vencer darei do maná escondido, e lhe darei uma pedra branca, e na pedra um novo nome escrito, o qual ninguém conhece senão aquele que o recebe.' },
      { v: 18, en: '“To the angel of the assembly in Thyatira write: “The Son of God, who has his eyes like a flame of fire, and his feet are like burnished brass, says these things:', pt: 'Ao anjo da igreja em Tiatira escreve: Isto diz o Filho de Deus, que tem os olhos como chama de fogo, e os pés semelhantes a latão reluzente:' },
      { v: 19, en: '“I know your works, your love, faith, service, patient endurance, and that your last works are more than the first.', pt: 'Conheço as tuas obras, e o teu amor, e a tua fé, e o teu serviço, e a tua perseverança, e sei que as tuas últimas obras são mais numerosas que as primeiras.' },
      { v: 20, en: 'But I have this against you, that you tolerate your woman, Jezebel, who calls herself a prophetess. She teaches and seduces my servants to commit sexual immorality, and to eat things sacrificed to idols.', pt: 'Mas tenho contra ti que toleras a mulher Jezabel, que se diz profetisa; ela ensina e seduz os meus servos a se prostituírem e a comerem das coisas sacrificdas a ídolos;' },
      { v: 21, en: 'I gave her time to repent, but she refuses to repent of her sexual immorality.', pt: 'e dei-lhe tempo para que se arrependesse; e ela não quer arrepender-se da sua prostituição.' },
      { v: 22, en: 'Behold, I will throw her into a bed, and those who commit adultery with her into great oppression, unless they repent of her works.', pt: 'Eis que a lanço num leito de dores, e numa grande tribulação os que cometem adultério com ela, se não se arrependerem das obras dela;' },
      { v: 23, en: 'I will kill her children with Death, and all the assemblies will know that I am he who searches the minds and hearts. I will give to each one of you according to your deeds.', pt: 'e ferirei de morte a seus filhos, e todas as igrejas saberão que eu sou aquele que esquadrinha os rins e os corações; e darei a cada um de vós segundo as suas obras.' },
      { v: 24, en: 'But to you I say, to the rest who are in Thyatira, as many as don’t have this teaching, who don’t know what some call ‘the deep things of Satan,’ to you I say, I am not putting any other burden on you.', pt: 'Digo-vos, porém, a vós os demais que estão em Tiatira, a todos quantos não têm esta doutrina, e não conhecem as chamadas profundezas de Satanás, que outra carga vos não porei;' },
      { v: 25, en: 'Nevertheless, hold that which you have firmly until I come.', pt: 'mas o que tendes, retende-o até que eu venha.' },
      { v: 26, en: 'He who overcomes, and he who keeps my works to the end, to him I will give authority over the nations.', pt: 'Ao que vencer, e ao que guardar as minhas obras até o fim, eu lhe darei autoridade sobre as nações,' },
      { v: 27, en: 'He will rule them with a rod of iron, shattering them like clay pots; as I also have received of my Father:', pt: 'e com vara de ferro as regerá, quebrando-as do modo como são quebrados os vasos do oleiro, assim como eu recebi autoridade de meu Pai;' },
      { v: 28, en: 'and I will give him the morning star.', pt: 'também lhe darei a estrela da manhã.' },
      { v: 29, en: 'He who has an ear, let him hear what the Spirit says to the assemblies.', pt: 'Quem tem ouvidos, ouça o que o Espírito dia às igrejas.' },
    ],
    3: [
      { v: 1, en: '“And to the angel of the assembly in Sardis write: “He who has the seven Spirits of God, and the seven stars says these things: “I know your works, that you have a reputation of being alive, but you are dead.', pt: 'Ao anjo da igreja em Sardes escreve: Isto diz aquele que tem os sete espíritos de Deus, e as estrelas: Conheço as tuas obras; tens nome de que vives, e estás morto.' },
      { v: 2, en: 'Wake up, and keep the things that remain, which you were about to throw away, for I have found no works of yours perfected before my God.', pt: 'Sê vigilante, e confirma o restante, que estava para morrer; porque não tenho achado as tuas obras perfeitas diante do meu Deus.' },
      { v: 3, en: 'Remember therefore how you have received and heard. Keep it, and repent. If therefore you won’t watch, I will come as a thief, and you won’t know what hour I will come upon you.', pt: 'Lembra-te, portanto, do que tens recebido e ouvido, e guarda-o, e arrepende-te. Pois se não vigiares, virei como um ladrão, e não saberás a que hora sobre ti virei.' },
      { v: 4, en: 'Nevertheless you have a few names in Sardis that did not defile their garments. They will walk with me in white, for they are worthy.', pt: 'Mas também tens em Sardes algumas pessoas que não contaminaram as suas vestes e comigo andarão vestidas de branco, porquanto são dignas.' },
      { v: 5, en: 'He who overcomes will be arrayed in white garments, and I will in no way blot his name out of the book of life, and I will confess his name before my Father, and before his angels.', pt: 'O que vencer será assim vestido de vestes brancas, e de maneira nenhuma riscarei o seu nome do livro da vida; antes confessarei o seu nome diante de meu Pai e diante dos seus anjos.' },
      { v: 6, en: 'He who has an ear, let him hear what the Spirit says to the assemblies.', pt: 'Quem tem ouvidos, ouça o que o espírito diz às igrejas.' },
      { v: 7, en: '“To the angel of the assembly in Philadelphia write: “He who is holy, he who is true, he who has the key of David, he who opens and no one can shut, and who shuts and no one opens, says these things:', pt: 'Ao anjo da igreja em Filadélfia escreve: Isto diz o que é santo, o que é verdadeiro, o que tem a chave de Davi; o que abre, e ninguém fecha; e fecha, e ninguém abre:' },
      { v: 8, en: '“I know your works (behold, I have set before you an open door, which no one can shut), that you have a little power, and kept my word, and didn’t deny my name.', pt: 'Conheço as tuas obras (eis que tenho posto diante de ti uma porta aberta, que ninguém pode fechar), que tens pouca força, entretanto guardaste a minha palavra e não negaste o meu nome.' },
      { v: 9, en: 'Behold, I give some of the synagogue of Satan, of those who say they are Jews, and they are not, but lie. Behold, I will make them to come and worship before your feet, and to know that I have loved you.', pt: 'Eis que farei aos da sinagoga de Satanás, aos que se dizem judeus, e não o são, mas mentem, - eis que farei que venham, e adorem prostrados aos teus pés, e saibam que eu te amo.' },
      { v: 10, en: 'Because you kept my command to endure, I also will keep you from the hour of testing, which is to come on the whole world, to test those who dwell on the earth.', pt: 'Porquanto guardaste a palavra da minha perseverança, também eu te guardarei da hora da provação que há de vir sobre o mundo inteiro, para pôr à prova os que habitam sobre a terra.' },
      { v: 11, en: 'I am coming quickly! Hold firmly that which you have, so that no one takes your crown.', pt: 'Venho sem demora; guarda o que tens, para que ninguém tome a tua coroa.' },
      { v: 12, en: 'He who overcomes, I will make him a pillar in the temple of my God, and he will go out from there no more. I will write on him the name of my God, and the name of the city of my God, the new Jerusalem, which comes down out of heaven from my God, and my own new name.', pt: 'A quem vencer, eu o farei coluna no templo do meu Deus, donde jamais sairá; e escreverei sobre ele o nome do meu Deus, e o nome da cidade do meu Deus, a nova Jerusalém, que desce do céu, da parte do meu Deus, e também o meu novo nome.' },
      { v: 13, en: 'He who has an ear, let him hear what the Spirit says to the assemblies.', pt: 'Quem tem ouvidos, ouça o que o Espírito diz às igrejas.' },
      { v: 14, en: '“To the angel of the assembly in Laodicea write: “The Amen, the Faithful and True Witness, the Beginning of God’s creation, says these things:', pt: 'Ao anjo da igreja em Laodicéia escreve: Isto diz o Amém, a testemunha fiel e verdadeira, o pricípio da criação de Deus:' },
      { v: 15, en: '“I know your works, that you are neither cold nor hot. I wish you were cold or hot.', pt: 'Conheço as tuas obras, que nem és frio nem quente; oxalá foras frio ou quente!' },
      { v: 16, en: 'So, because you are lukewarm, and neither hot nor cold, I will vomit you out of my mouth.', pt: 'Assim, porque és morno, e não és quente nem frio, vomitar-te-ei da minha boca.' },
      { v: 17, en: 'Because you say, ‘I am rich, and have gotten riches, and have need of nothing;’ and don’t know that you are the wretched one, miserable, poor, blind, and naked;', pt: 'Porquanto dizes: Rico sou, e estou enriquecido, e de nada tenho falta; e não sabes que és um coitado, e miserável, e pobre, e cego, e nu;' },
      { v: 18, en: 'I counsel you to buy from me gold refined by fire, that you may become rich; and white garments, that you may clothe yourself, and that the shame of your nakedness may not be revealed; and eye salve to anoint your eyes, that you may see.', pt: 'aconselho-te que de mim compres ouro refinado no fogo, para que te enriqueças; e vestes brancas, para que te vistas, e não seja manifesta a vergonha da tua nudez; e colírio, a fim de ungires os teus olhos, para que vejas.' },
      { v: 19, en: 'As many as I love, I reprove and chasten. Be zealous therefore, and repent.', pt: 'Eu repreendo e castigo a todos quantos amo: sê pois zeloso, e arrepende-te.' },
      { v: 20, en: 'Behold, I stand at the door and knock. If anyone hears my voice and opens the door, then I will come in to him, and will dine with him, and he with me.', pt: 'Eis que estou à porta e bato; se alguém ouvir a minha voz, e abrir a porta, entrarei em sua casa, e com ele cearei, e ele comigo.' },
      { v: 21, en: 'He who overcomes, I will give to him to sit down with me on my throne, as I also overcame, and sat down with my Father on his throne.', pt: 'Ao que vencer, eu lhe concederei que se assente comigo no meu trono.' },
      { v: 22, en: 'He who has an ear, let him hear what the Spirit says to the assemblies.”', pt: 'Quem tem ouvidos, ouça o que o Espírito diz às igrejas.' },
    ],
    4: [
      { v: 1, en: 'After these things I looked and saw a door opened in heaven, and the first voice that I heard, like a trumpet speaking with me, was one saying, “Come up here, and I will show you the things which must happen after this.”', pt: 'Depois destas coisas, olhei, e eis que estava uma porta aberta no céu, e a primeira voz que ouvira, voz como de trombeta, falando comigo, disse: Sobe aqui, e mostrar-te-ei as coisas que depois destas devem acontecer.' },
      { v: 2, en: 'Immediately I was in the Spirit. Behold, there was a throne set in heaven, and one sitting on the throne', pt: 'Imediatamente fui arrebatado em espírito, e eis que um trono estava posto no céu, e um assentado sobre o trono;' },
      { v: 3, en: 'that looked like a jasper stone and a sardius. There was a rainbow around the throne, like an emerald to look at.', pt: 'e aquele que estava assentado era, na aparência, semelhante a uma pedra de jaspe e sárdio; e havia ao redor do trono um arco-íris semelhante, na aparência, à esmeralda.' },
      { v: 4, en: 'Around the throne were twenty-four thrones. On the thrones were twenty-four elders sitting, dressed in white garments, with crowns of gold on their heads.', pt: 'Havia também ao redor do trono vinte e quatro tronos; e sobre os tronos vi assentados vinte e quatro anciãos, vestidos de branco, que tinham nas suas cabeças coroas de ouro.' },
      { v: 5, en: 'Out of the throne proceed lightnings, sounds, and thunders. There were seven lamps of fire burning before his throne, which are the seven Spirits of God.', pt: 'E do trono saíam relâmpagos, e vozes, e trovões; e diante do trono ardiam sete lâmpadas de fogo, as quais são os sete espíritos de Deus;' },
      { v: 6, en: 'Before the throne was something like a sea of glass, similar to crystal. In the middle of the throne, and around the throne were four living creatures full of eyes before and behind.', pt: 'também havia diante do trono como que um mar de vidro, semelhante ao cristal; e ao redor do trono, um ao meio de cada lado, quatro seres viventes cheios de olhos por diante e por detrás;' },
      { v: 7, en: 'The first creature was like a lion, and the second creature like a calf, and the third creature had a face like a man, and the fourth was like a flying eagle.', pt: 'e o primeiro ser era semelhante a um leão; o segundo ser, semelhante a um touro; tinha o terceiro ser o rosto como de homem; e o quarto ser era semelhante a uma águia voando.' },
      { v: 8, en: 'The four living creatures, each one of them having six wings, are full of eyes around and within. They have no rest day and night, saying, “Holy, holy, holy is the Lord God, the Almighty, who was and who is and who is to come!”', pt: 'Os quatro seres viventes tinham, cada um, seis asas, e ao redor e por dentro estavam cheios de olhos; e não têm descanso nem de noite, dizendo: Santo, Santo, Santo é o Senhor Deus, o Todo-Poderoso, aquele que era, e que é, e que há de vir.' },
      { v: 9, en: 'When the living creatures give glory, honor, and thanks to him who sits on the throne, to him who lives forever and ever,', pt: 'E, sempre que os seres viventes davam glória e honra e ações de graças ao que estava assentado sobre o trono, ao que vive pelos séculos dos séculos,' },
      { v: 10, en: 'the twenty-four elders fall down before him who sits on the throne, and worship him who lives forever and ever, and throw their crowns before the throne, saying,', pt: 'os vinte e quatro anciãos prostravam-se diante do que estava assentado sobre o trono, e adoravam ao que vive pelos séculos dos séculos; e lançavam as suas coroas diante do trono, dizendo:' },
      { v: 11, en: '“Worthy are you, our Lord and God, the Holy One, to receive the glory, the honor, and the power, for you created all things, and because of your desire they existed, and were created!”', pt: 'Digno és, Senhor nosso e Deus nosso, de receber a glória e a honra e o poder; porque tu criaste todas as coisas, e por tua vontade existiram e foram criadas.' },
    ],
    5: [
      { v: 1, en: 'I saw, in the right hand of him who sat on the throne, a book written inside and outside, sealed shut with seven seals.', pt: 'Vi na destra do que estava assentado sobre o trono um livro escrito por dentro e por fora, bem selado com sete selos.' },
      { v: 2, en: 'I saw a mighty angel proclaiming with a loud voice, “Who is worthy to open the book, and to break its seals?”', pt: 'Vi também um anjo forte, clamando com grande voz: Quem é digno de abrir o livro e de romper os seus selos?' },
      { v: 3, en: 'No one in heaven above, or on the earth, or under the earth, was able to open the book, or to look in it.', pt: 'E ninguém no céu, nem na terra, nem debaixo da terra, podia abrir o livro, nem olhar para ele.' },
      { v: 4, en: 'And I wept much, because no one was found worthy to open the book, or to look in it.', pt: 'E eu chorava muito, porque não fora achado ninguém digno de abrir o livro nem de olhar para ele.' },
      { v: 5, en: 'One of the elders said to me, “Don’t weep. Behold, the Lion who is of the tribe of Judah, the Root of David, has overcome; he who opens the book and its seven seals.”', pt: 'E disse-me um dentre os anciãos: Não chores; eis que o Leão da tribo de Judá, a raiz de Davi, venceu para abrir o livro e romper os sete selos.' },
      { v: 6, en: 'I saw in the middle of the throne and of the four living creatures, and in the middle of the elders, a Lamb standing, as though it had been slain, having seven horns, and seven eyes, which are the seven Spirits of God, sent out into all the earth.', pt: 'Nisto vi, entre o trono e os quatro seres viventes, no meio dos anciãos, um Cordeiro em pé, como havendo sido morto, e tinha sete chifres e sete olhos, que são os sete espíritos de Deus, enviados por toda a terra.' },
      { v: 7, en: 'Then he came, and he took it out of the right hand of him who sat on the throne.', pt: 'E veio e tomou o livro da destra do que estava assentado sobre o trono.' },
      { v: 8, en: 'Now when he had taken the book, the four living creatures and the twenty-four elders fell down before the Lamb, each one having a harp, and golden bowls full of incense, which are the prayers of the saints.', pt: 'Logo que tomou o livro, os quatro seres viventes e os vinte e quatro anciãos prostraram-se diante do Cordeiro, tendo cada um deles uma harpa e taças de ouro cheias de incenso, que são as orações dos santos.' },
      { v: 9, en: 'They sang a new song, saying, “You are worthy to take the book, and to open its seals: for you were killed, and bought us for God with your blood, out of every tribe, language, people, and nation,', pt: 'E cantavam um cântico novo, dizendo: Digno és de tomar o livro, e de abrir os seus selos; porque foste morto, e com o teu sangue compraste para Deus homens de toda tribo, e língua, e povo e nação;' },
      { v: 10, en: 'and made us kings and priests to our God, and we will reign on the earth.”', pt: 'e para o nosso Deus os fizeste reino, e sacerdotes; e eles reinarão sobre a terra.' },
      { v: 11, en: 'I saw, and I heard something like a voice of many angels around the throne, the living creatures, and the elders; and the number of them was ten thousands of ten thousands, and thousands of thousands;', pt: 'E olhei, e vi a voz de muitos anjos ao redor do trono e dos seres viventes e dos anciãos; e o número deles era miríades de miríades; e o número deles era miríades de miríades e milhares de milhares,' },
      { v: 12, en: 'saying with a loud voice, “Worthy is the Lamb who has been killed to receive the power, wealth, wisdom, strength, honor, glory, and blessing!”', pt: 'que com grande voz diziam: Digno é o Cordeiro, que foi morto, de receber o poder, e riqueza, e sabedoria, e força, e honra, e glória, e louvor.' },
      { v: 13, en: 'I heard every created thing which is in heaven, on the earth, under the earth, on the sea, and everything in them, saying, “To him who sits on the throne, and to the Lamb be the blessing, the honor, the glory, and the dominion, forever and ever! Amen!”', pt: 'Ouvi também a toda criatura que está no céu, e na terra, e debaixo da terra, e no mar, e a todas as coisas que neles há, dizerem: Ao que está assentado sobre o trono, e ao Cordeiro, seja o louvor, e a honra, e a glória, e o domínio pelos séculos dos séculos:' },
      { v: 14, en: 'The four living creatures said, “Amen!” Then the elders fell down and worshiped.', pt: 'e os quatro seres viventes diziam: Amém. E os anciãos prostraram-se e adoraram.' },
    ],
    6: [
      { v: 1, en: 'I saw that the Lamb opened one of the seven seals, and I heard one of the four living creatures saying, as with a voice of thunder, “Come and see!”', pt: 'E vi quando o Cordeiro abriu um dos sete selos, e ouvi um dos quatro seres viventes dizer numa voz como de trovão: Vem!' },
      { v: 2, en: 'And behold, a white horse, and he who sat on it had a bow. A crown was given to him, and he came out conquering, and to conquer.', pt: 'Olhei, e eis um cavalo branco; e o que estava montado nele tinha um arco; e foi-lhe dada uma coroa, e saiu vencendo, e para vencer.' },
      { v: 3, en: 'When he opened the second seal, I heard the second living creature saying, “Come!”', pt: 'Quando ele abriu o segundo selo, ouvi o segundo ser vivente dizer: Vem!' },
      { v: 4, en: 'Another came out, a red horse. To him who sat on it was given power to take peace from the earth, and that they should kill one another. There was given to him a great sword.', pt: 'E saiu outro cavalo, um cavalo vermelho; e ao que estava montado nele foi dado que tirasse a paz da terra, de modo que os homens se matassem uns aos outros; e foi-lhe dada uma grande espada.' },
      { v: 5, en: 'When he opened the third seal, I heard the third living creature saying, “Come and see!” And behold, a black horse, and he who sat on it had a balance in his hand.', pt: 'Quando abriu o terceiro selo, ouvi o terceiro ser vivente dizer: Vem! E olhei, e eis um cavalo preto; e o que estava montado nele tinha uma balança na mão.' },
      { v: 6, en: 'I heard a voice in the middle of the four living creatures saying, “A choenix of wheat for a denarius, and three choenix of barley for a denarius! Don’t damage the oil and the wine!”', pt: 'E ouvi como que uma voz no meio dos quatro seres viventes, que dizia: Um queniz de trigo por um denário, e três quenizes de cevada por um denário; e não danifiques o azeite e o vinho.' },
      { v: 7, en: 'When he opened the fourth seal, I heard the fourth living creature saying, “Come and see!”', pt: 'Quando abriu o quarto selo, ouvi a voz do quarto ser vivente dizer: Vem!' },
      { v: 8, en: 'And behold, a pale horse, and he who sat on it, his name was Death. Hades followed with him. Authority over one fourth of the earth, to kill with the sword, with famine, with death, and by the wild animals of the earth was given to him.', pt: 'E olhei, e eis um cavalo amarelo, e o que estava montado nele chamava-se Morte; e o hades seguia com ele; e foi-lhe dada autoridade sobre a quarta parte da terra, para matar com a espada, e com a fome, e com a peste, e com as feras da terra.' },
      { v: 9, en: 'When he opened the fifth seal, I saw underneath the altar the souls of those who had been killed for the Word of God, and for the testimony of the Lamb which they had.', pt: 'Quando abriu o quinto selo, vi debaixo do altar as almas dos que tinham sido mortos por causa da palavra de Deus e por causa do testemunho que deram.' },
      { v: 10, en: 'They cried with a loud voice, saying, “How long, Master, the holy and true, until you judge and avenge our blood on those who dwell on the earth?”', pt: 'E clamaram com grande voz, dizendo: Até quando, ó Soberano, santo e verdadeiro, não julgas e vingas o nosso sangue dos que habitam sobre a terra?.' },
      { v: 11, en: 'A long white robe was given to each of them. They were told that they should rest yet for a while, until their fellow servants and their brothers, who would also be killed even as they were, should complete their course.', pt: 'E foram dadas a cada um deles compridas vestes brancas e foi-lhes dito que repousassem ainda por um pouco de tempo, até que se completasse o número de seus conservos, que haviam de ser mortos, como também eles o foram.' },
      { v: 12, en: 'I saw when he opened the sixth seal, and there was a great earthquake. The sun became black as sackcloth made of hair, and the whole moon became as blood.', pt: 'E vi quando abriu o sexto selo, e houve um grande terremoto; e o sol tornou-se negro como saco de cilício, e a lua toda tornou-se como sangue;' },
      { v: 13, en: 'The stars of the sky fell to the earth, like a fig tree dropping its unripe figs when it is shaken by a great wind.', pt: 'e as estrelas do céu caíram sobre a terra, como quando a figueira, sacudida por um vento forte, deixa cair os seus figos verdes.' },
      { v: 14, en: 'The sky was removed like a scroll when it is rolled up. Every mountain and island were moved out of their places.', pt: 'E o céu recolheu-se como um livro que se enrola; e todos os montes e ilhas foram removidos dos seus lugares.' },
      { v: 15, en: 'The kings of the earth, the princes, the commanding officers, the rich, the strong, and every slave and free person, hid themselves in the caves and in the rocks of the mountains.', pt: 'E os reis da terra, e os grandes, e os chefes militares, e os ricos, e os poderosos, e todo escravo, e todo livre, se esconderam nas cavernas e nas rochas das montanhas;' },
      { v: 16, en: 'They told the mountains and the rocks, “Fall on us, and hide us from the face of him who sits on the throne, and from the wrath of the Lamb,', pt: 'e diziam aos montes e aos rochedos: Caí sobre nós, e escondei-nos da face daquele que está assentado sobre o trono, e da ira do Cordeiro;' },
      { v: 17, en: 'for the great day of his wrath has come; and who is able to stand?”', pt: 'porque é vindo o grande dia da ira deles; e quem poderá subsistir?' },
    ],
    7: [
      { v: 1, en: 'After this, I saw four angels standing at the four corners of the earth, holding the four winds of the earth, so that no wind would blow on the earth, or on the sea, or on any tree.', pt: 'Depois disto vi quatro anjos em pé nos quatro cantos da terra, retendo os quatro ventos da terra, para que nenhum vento soprasse sobre a terra, nem sobre o mar, nem contra árvore alguma.' },
      { v: 2, en: 'I saw another angel ascend from the sunrise, having the seal of the living God. He cried with a loud voice to the four angels to whom it was given to harm the earth and the sea,', pt: 'E vi outro anjo subir do lado do sol nascente, tendo o selo do Deus vivo; e clamou com grande voz aos quatro anjos, quem fora dado que danificassem a terra e o mar,' },
      { v: 3, en: 'saying, “Don’t harm the earth, neither the sea, nor the trees, until we have sealed the bondservants of our God on their foreheads!”', pt: 'dizendo: Não danifiques a terra, nem o mar, nem as árvores, até que selemos na sua fronte os servos do nosso Deus.' },
      { v: 4, en: 'I heard the number of those who were sealed, one hundred forty-four thousand, sealed out of every tribe of the children of Israel:', pt: 'E ouvi o número dos que foram assinalados com o selo, cento e quarenta e quatro mil de todas as tribos dos filhos de Israel:' },
      { v: 5, en: 'of the tribe of Judah were sealed twelve thousand, of the tribe of Reuben twelve thousand, of the tribe of Gad twelve thousand,', pt: 'da tribo de Judá havia doze mil assinalados; da tribo de Rúben, doze mil; da tribo de Gade, doze mil;' },
      { v: 6, en: 'of the tribe of Asher twelve thousand, of the tribe of Naphtali twelve thousand, of the tribe of Manasseh twelve thousand,', pt: 'da tribo de Aser, doze mil; da tribo de Naftali, doze mil; da tribo de Manassés, doze mil;' },
      { v: 7, en: 'of the tribe of Simeon twelve thousand, of the tribe of Levi twelve thousand, of the tribe of Issachar twelve thousand,', pt: 'da tribo de Simeão, doze mil; da tribo de Levi, doze mil; da tribo de Issacar, doze mil;' },
      { v: 8, en: 'of the tribe of Zebulun twelve thousand, of the tribe of Joseph twelve thousand, of the tribe of Benjamin were sealed twelve thousand.', pt: 'da tribo de Zabulom, doze mil; da tribo de José, doze mil; da tribo de Benjamim, doze mil assinalados.' },
      { v: 9, en: 'After these things I looked, and behold, a great multitude, which no man could count, out of every nation and of all tribes, peoples, and languages, standing before the throne and before the Lamb, dressed in white robes, with palm branches in their hands.', pt: 'Depois destas coisas olhei, e eis uma grande multidão, que ninguém podia contar, de todas as nações, tribos, povos e línguas, que estavam em pé diante do trono e em presença do Cordeiro, trajando compridas vestes brancas, e com palmas nas mãos;' },
      { v: 10, en: 'They cried with a loud voice, saying, “Salvation be to our God, who sits on the throne, and to the Lamb!”', pt: 'e clamavam com grande voz: Salvação ao nosso Deus, que está assentado sobre o trono, e ao Cordeiro.' },
      { v: 11, en: 'All the angels were standing around the throne, the elders, and the four living creatures; and they fell on their faces before his throne, and worshiped God,', pt: 'E todos os anjos estavam em pé ao redor do trono e dos anciãos e dos quatro seres viventes, e prostraram-se diante do trono sobre seus rostos, e adoraram a Deus,' },
      { v: 12, en: 'saying, “Amen! Blessing, glory, wisdom, thanksgiving, honor, power, and might, be to our God forever and ever! Amen.”', pt: 'dizendo: Amém. Louvor, e glória, e sabedoria, e ações de graças, e honra, e poder, e força ao nosso Deus, pelos séculos dos séculos. Amém.' },
      { v: 13, en: 'One of the elders answered, saying to me, “These who are arrayed in the white robes, who are they, and from where did they come?”', pt: 'E um dos anciãos me perguntou: Estes que trajam as compridas vestes brancas, quem são eles e donde vieram?' },
      { v: 14, en: 'I told him, “My lord, you know.” He said to me, “These are those who came out of the great tribulation. They washed their robes, and made them white in the Lamb’s blood.', pt: 'Respondi-lhe: Meu Senhor, tu sabes. Disse-me ele: Estes são os que vêm da grande tribulação, e levaram as suas vestes e as branquearam no sangue do Cordeiro.' },
      { v: 15, en: 'Therefore they are before the throne of God, they serve him day and night in his temple. He who sits on the throne will spread his tabernacle over them.', pt: 'Por isso estão diante do trono de Deus, e o servem de dia e de noite no seu santuário; e aquele que está assentado sobre o trono estenderá o seu tabernáculo sobre eles.' },
      { v: 16, en: 'They will never be hungry, neither thirsty any more; neither will the sun beat on them, nor any heat;', pt: 'Nunca mais terão fome, nunca mais terão sede; nem cairá sobre eles o sol, nem calor algum;' },
      { v: 17, en: 'for the Lamb who is in the middle of the throne shepherds them, and leads them to springs of life-giving waters. And God will wipe away every tear from their eyes.”', pt: 'porque o Cordeiro que está no meio, diante do trono, os apascentará e os conduzirá às fontes das águas da vida; e Deus lhes enxugará dos olhos toda lágrima.' },
    ],
    8: [
      { v: 1, en: 'When he opened the seventh seal, there was silence in heaven for about half an hour.', pt: 'Quando abriu o sétimo selo, fez-se silêncio no céu, quase por meia hora.' },
      { v: 2, en: 'I saw the seven angels who stand before God, and seven trumpets were given to them.', pt: 'E vi os sete anjos que estavam em pé diante de Deus, e lhes foram dadas sete trombetas.' },
      { v: 3, en: 'Another angel came and stood over the altar, having a golden censer. Much incense was given to him, that he should add it to the prayers of all the saints on the golden altar which was before the throne.', pt: 'Veio outro anjo, e pôs-se junto ao altar, tendo um incensário de ouro; e foi-lhe dado muito incenso, para que o oferecesse com as orações de todos os santos sobre o altar de ouro que está diante do trono.' },
      { v: 4, en: 'The smoke of the incense, with the prayers of the saints, went up before God out of the angel’s hand.', pt: 'E da mão do anjo subiu diante de Deus a fumaça do incenso com as orações dos santos.' },
      { v: 5, en: 'The angel took the censer, and he filled it with the fire of the altar, and threw it on the earth. Thunders, sounds, lightnings, and an earthquake followed.', pt: 'Depois do anjo tomou o incensário, encheu-o do fogo do altar e o lançou sobre a terra; e houve trovões, vozes, relâmpagos e terremoto.' },
      { v: 6, en: 'The seven angels who had the seven trumpets prepared themselves to sound.', pt: 'Então os sete anjos que tinham as sete trombetas prepararam-se para tocar.' },
      { v: 7, en: 'The first sounded, and there followed hail and fire, mixed with blood, and they were thrown to the earth. One third of the earth was burned up, and one third of the trees were burned up, and all green grass was burned up.', pt: 'O primeiro anjo tocou a sua trombeta, e houve saraiva e fogo misturado com sangue, que foram lançados na terra; e foi queimada a terça parte da terra, a terça parte das árvores, e toda a erva verde.' },
      { v: 8, en: 'The second angel sounded, and something like a great burning mountain was thrown into the sea. One third of the sea became blood,', pt: 'O segundo anjo tocou a sua trombeta, e foi lançado no mar como que um grande monte ardendo em fogo, e tornou-se em sangue a terça parte do mar.' },
      { v: 9, en: 'and one third of the living creatures which were in the sea died. One third of the ships were destroyed.', pt: 'E morreu a terça parte das criaturas viventes que havia no mar, e foi destruída a terça parte dos navios.' },
      { v: 10, en: 'The third angel sounded, and a great star fell from the sky, burning like a torch, and it fell on one third of the rivers, and on the springs of the waters.', pt: 'O terceiro anjo tocou a sua trombeta, e caiu do céu uma grande estrela, ardendo como uma tocha, e caiu sobre a terça parte dos rios, e sobre as fontes das águas.' },
      { v: 11, en: 'The name of the star is called “Wormwood.” One third of the waters became wormwood. Many people died from the waters, because they were made bitter.', pt: 'O nome da estrela era Absinto; e a terça parte das águas tornou-se em absinto, e muitos homens morreram das águas, porque se tornaram amargas.' },
      { v: 12, en: 'The fourth angel sounded, and one third of the sun was struck, and one third of the moon, and one third of the stars; so that one third of them would be darkened, and the day wouldn’t shine for one third of it, and the night in the same way.', pt: 'O quarto anjo tocou a sua trombeta, e foi ferida a terça parte do sol, a terça parte da lua, e a terça parte das estrelas; para que a terça parte deles se escurecesse, e a terça parte do dia não brilhante, e semelhantemente a da noite.' },
      { v: 13, en: 'I saw, and I heard an eagle, flying in mid heaven, saying with a loud voice, “Woe! Woe! Woe for those who dwell on the earth, because of the other voices of the trumpets of the three angels, who are yet to sound!”', pt: 'E olhei, e ouvi uma águia que, voando pelo meio do céu, dizia com grande voz: Ai, ai, ai dos que habitam sobre a terra! por causa dos outros toques de trombeta dos três anjos que ainda vão tocar.' },
    ],
    9: [
      { v: 1, en: 'The fifth angel sounded, and I saw a star from the sky which had fallen to the earth. The key to the pit of the abyss was given to him.', pt: 'O quinto anjo tocou a sua trombeta, e vi uma estrela que do céu caíra sobre a terra; e foi-lhe dada a chave do poço do abismo.' },
      { v: 2, en: 'He opened the pit of the abyss, and smoke went up out of the pit, like the smoke from a burning furnace. The sun and the air were darkened because of the smoke from the pit.', pt: 'E abriu o poço do abismo, e subiu fumaça do poço, como fumaça de uma grande fornalha; e com a fumaça do poço escureceram-se o sol e o ar.' },
      { v: 3, en: 'Then out of the smoke came locusts on the earth, and power was given to them, as the scorpions of the earth have power.', pt: 'Da fumaça saíram gafanhotos sobre a terra; e foi-lhes dado poder, como o que têm os escorpiões da terra.' },
      { v: 4, en: 'They were told that they should not hurt the grass of the earth, neither any green thing, neither any tree, but only those people who don’t have God’s seal on their foreheads.', pt: 'Foi-lhes dito que não fizessem dano à erva da terra, nem a verdura alguma, nem a árvore alguma, mas somente aos homens que não têm na fronte o selo de Deus.' },
      { v: 5, en: 'They were given power, not to kill them, but to torment them for five months. Their torment was like the torment of a scorpion, when it strikes a person.', pt: 'Foi-lhes permitido, não que os matassem, mas que por cinco meses os atormentassem. E o seu tormento era semelhante ao tormento do escorpião, quando fere o homem.' },
      { v: 6, en: 'In those days people will seek death, and will in no way find it. They will desire to die, and death will flee from them.', pt: 'Naqueles dias os homens buscarão a morte, e de modo algum a acharão; e desejarão morrer, e a morte fugirá deles.' },
      { v: 7, en: 'The shapes of the locusts were like horses prepared for war. On their heads were something like golden crowns, and their faces were like people’s faces.', pt: 'A aparência dos gafanhotos era semelhante à de cavalos aparelhados para a guerra; e sobre as suas cabeças havia como que umas coroas semelhantes ao ouro; e os seus rostos eram como rostos de homens.' },
      { v: 8, en: 'They had hair like women’s hair, and their teeth were like those of lions.', pt: 'Tinham cabelos como cabelos de mulheres, e os seus dentes eram como os de leões.' },
      { v: 9, en: 'They had breastplates, like breastplates of iron. The sound of their wings was like the sound of chariots, or of many horses rushing to war.', pt: 'Tinham couraças como couraças de ferro; e o ruído das suas asas era como o ruído de carros de muitos cavalos que correm ao combate.' },
      { v: 10, en: 'They have tails like those of scorpions, and stings. In their tails they have power to harm men for five months.', pt: 'Tinham caudas com ferrões, semelhantes às caudas dos escorpiões; e nas suas caudas estava o seu poder para fazer dano aos homens por cinco meses.' },
      { v: 11, en: 'They have over them as king the angel of the abyss. His name in Hebrew is “Abaddon”, but in Greek, he has the name “Apollyon”.', pt: 'Tinham sobre si como rei o anjo do abismo, cujo nome em hebraico é Abadom e em grego Apoliom.' },
      { v: 12, en: 'The first woe is past. Behold, there are still two woes coming after this.', pt: 'Passado é já um ai; eis que depois disso vêm ainda dois ais.' },
      { v: 13, en: 'The sixth angel sounded. I heard a voice from the horns of the golden altar which is before God,', pt: 'O sexto anjo tocou a sua trombeta; e ouvi uma voz que vinha das quatro pontas do altar de ouro que estava diante de Deus,' },
      { v: 14, en: 'saying to the sixth angel who had the trumpet, “Free the four angels who are bound at the great river Euphrates!”', pt: 'a qual dizia ao sexto anjo, que tinha a trombeta: Solta os quatro anjos que se acham presos junto do grande rio Eufrates.' },
      { v: 15, en: 'The four angels were freed who had been prepared for that hour and day and month and year, so that they might kill one third of mankind.', pt: 'E foram soltos os quatro anjos que haviam sido preparados para aquela hora e dia e mês e ano, a fim de matarem a terça parte dos homens.' },
      { v: 16, en: 'The number of the armies of the horsemen was two hundred million. I heard the number of them.', pt: 'O número dos exércitos dos cavaleiros era de duas miríades de miríades; pois ouvi o número deles.' },
      { v: 17, en: 'Thus I saw the horses in the vision, and those who sat on them, having breastplates of fiery red, hyacinth blue, and sulfur yellow; and the horses’ heads resembled lions’ heads. Out of their mouths proceed fire, smoke, and sulfur.', pt: 'E assim vi os cavalos nesta visão: os que sobre eles estavam montados tinham couraças de fogo, e de jacinto, e de enxofre; e as cabeças dos cavalos eram como cabeças de leões; e de suas bocas saíam fogo, fumaça e enxofre.' },
      { v: 18, en: 'By these three plagues were one third of mankind killed: by the fire, the smoke, and the sulfur, which proceeded out of their mouths.', pt: 'Por estas três pragas foi morta a terça parte dos homens, isto é, pelo fogo, pela fumaça e pelo enxofre, que saíam das suas bocas.' },
      { v: 19, en: 'For the power of the horses is in their mouths, and in their tails. For their tails are like serpents, and have heads, and with them they harm.', pt: 'Porque o poder dos cavalos estava nas suas bocas e nas suas caudas. Porquanto as suas caudas eram semelhantes a serpentes, e tinham cabeças, e com elas causavam dano.' },
      { v: 20, en: 'The rest of mankind, who were not killed with these plagues, didn’t repent of the works of their hands, that they wouldn’t worship demons, and the idols of gold, and of silver, and of brass, and of stone, and of wood; which can’t see, hear, or walk.', pt: 'Os outros homens, que não foram mortos por estas pragas, não se arrependeram das obras das suas mãos, para deixarem de adorar aos demônios, e aos ídolos de ouro, de prata, de bronze, de pedra e de madeira, que nem podem ver, nem ouvir, nem andar.' },
      { v: 21, en: 'They didn’t repent of their murders, their sorceries, their sexual immorality, or their thefts.', pt: 'Também não se arrependeram dos seus homicídios, nem das suas feitiçarias, nem da sua prostituição, nem dos seus furtos.' },
    ],
    10: [
      { v: 1, en: 'I saw a mighty angel coming down out of the sky, clothed with a cloud. A rainbow was on his head. His face was like the sun, and his feet like pillars of fire.', pt: 'E vi outro anjo forte que descia do céu, vestido de uma nuvem; por cima da sua cabeça estava o arco-íris; o seu rosto era como o sol, e os seus pés como colunas de fogo,' },
      { v: 2, en: 'He had in his hand a little open book. He set his right foot on the sea, and his left on the land.', pt: 'e tinha na mão um livrinho aberto. Pôs o seu pé direito sobre o mar, e o esquerdo sobre a terra,' },
      { v: 3, en: 'He cried with a loud voice, as a lion roars. When he cried, the seven thunders uttered their voices.', pt: 'e clamou com grande voz, assim como ruge o leão; e quando clamou, os sete trovões fizeram soar as suas vozes.' },
      { v: 4, en: 'When the seven thunders sounded, I was about to write; but I heard a voice from the sky saying, “Seal up the things which the seven thunders said, and don’t write them.”', pt: 'Quando os sete trovões acabaram de soar eu já ia escrever, mas ouvi uma voz do céu, que dizia: Sela o que os sete trovões falaram, e não o escrevas.' },
      { v: 5, en: 'The angel whom I saw standing on the sea and on the land lifted up his right hand to the sky,', pt: 'O anjo que vi em pé sobre o mar e sobre a terra levantou a mão direita ao céu,' },
      { v: 6, en: 'and swore by him who lives forever and ever, who created heaven and the things that are in it, the earth and the things that are in it, and the sea and the things that are in it, that there will no longer be delay,', pt: 'e jurou por aquele que vive pelos séculos dos séculos, o qual criou o céu e o que nele há, e a terra e o que nela há, e o mar e o que nele há, que não haveria mais demora,' },
      { v: 7, en: 'but in the days of the voice of the seventh angel, when he is about to sound, then the mystery of God is finished, as he declared to his servants, the prophets.', pt: 'mas que nos dias da voz do sétimo anjo, quando este estivesse para tocar a trombeta, se cumpriria o mistério de Deus, como anunciou aos seus servos, os profetas.' },
      { v: 8, en: 'The voice which I heard from heaven, again speaking with me, said, “Go, take the book which is open in the hand of the angel who stands on the sea and on the land.”', pt: 'A voz que eu do céu tinha ouvido tornou a falar comigo, e disse: Vai, e toma o livro que está aberto na mão do anjo que se acha em pé sobre o mar e sobre a terra.' },
      { v: 9, en: 'I went to the angel, telling him to give me the little book. He said to me, “Take it, and eat it up. It will make your stomach bitter, but in your mouth it will be as sweet as honey.”', pt: 'E fui ter com o anjo e lhe pedi que me desse o livrinho. Disse-me ele: Toma-o, e come-o; ele fará amargo o teu ventre, mas na tua boca será doce como mel.' },
      { v: 10, en: 'I took the little book out of the angel’s hand, and ate it up. It was as sweet as honey in my mouth. When I had eaten it, my stomach was made bitter.', pt: 'Tomei o livrinho da mão do anjo, e o comi; e na minha boca era doce como mel; mas depois que o comi, o meu ventre ficou amargo.' },
      { v: 11, en: 'They told me, “You must prophesy again over many peoples, nations, languages, and kings.”', pt: 'Então me disseram: Importa que profetizes outra vez a muitos povos, e nações, e línguas, e reis.' },
    ],
    11: [
      { v: 1, en: 'A reed like a rod was given to me. Someone said, “Rise, and measure God’s temple, and the altar, and those who worship in it.', pt: 'Foi-me dada uma cana semelhante a uma vara; e foi-me dito: Levanta-te, mede o santuário de Deus, e o altar, e os que nele adoram.' },
      { v: 2, en: 'Leave out the court which is outside of the temple, and don’t measure it, for it has been given to the nations. They will tread the holy city under foot for forty-two months.', pt: 'Mas deixa o átrio que está fora do santuário, e não o meças; porque foi dado aos gentios; e eles pisarão a cidade santa por quarenta e dois meses.' },
      { v: 3, en: 'I will give power to my two witnesses, and they will prophesy one thousand two hundred sixty days, clothed in sackcloth.”', pt: 'E concederei às minhas duas testemunhas que, vestidas de saco, profetizem por mil duzentos e sessenta dias.' },
      { v: 4, en: 'These are the two olive trees and the two lamp stands, standing before the Lord of the earth.', pt: 'Estas são as duas oliveiras e os dois candeeiros que estão diante do Senhor da terra.' },
      { v: 5, en: 'If anyone desires to harm them, fire proceeds out of their mouth and devours their enemies. If anyone desires to harm them, he must be killed in this way.', pt: 'E, se alguém lhes quiser fazer mal, das suas bocas sairá fogo e devorará os seus inimigos; pois se alguém lhes quiser fazer mal, importa que assim seja morto.' },
      { v: 6, en: 'These have the power to shut up the sky, that it may not rain during the days of their prophecy. They have power over the waters, to turn them into blood, and to strike the earth with every plague, as often as they desire.', pt: 'Elas têm poder para fechar o céu, para que não chova durante os dias da sua profecia; e têm poder sobre as águas para convertê-las em sangue, e para ferir a terra com toda sorte de pragas, quantas vezes quiserem.' },
      { v: 7, en: 'When they have finished their testimony, the beast that comes up out of the abyss will make war with them, and overcome them, and kill them.', pt: 'E, quando acabarem o seu testemunho, a besta que sobe do abismo lhes fará guerra e as vencerá e matará.' },
      { v: 8, en: 'Their dead bodies will be in the street of the great city, which spiritually is called Sodom and Egypt, where also their Lord was crucified.', pt: 'E jazerão os seus corpos na praça da grande cidade, que espiritualmente se chama Sodoma e Egito, onde também o seu Senhor foi crucificado.' },
      { v: 9, en: 'From among the peoples, tribes, languages, and nations people will look at their dead bodies for three and a half days, and will not allow their dead bodies to be laid in a tomb.', pt: 'Homens de vários povos, e tribos e línguas, e nações verão os seus corpos por três dias e meio, e não permitirão que sejam sepultados.' },
      { v: 10, en: 'Those who dwell on the earth rejoice over them, and they will be glad. They will give gifts to one another, because these two prophets tormented those who dwell on the earth.', pt: 'E os que habitam sobre a terra se regozijarão sobre eles, e se alegrarão; e mandarão presentes uns aos outros, porquanto estes dois profetas atormentaram os que habitam sobre a terra.' },
      { v: 11, en: 'After the three and a half days, the breath of life from God entered into them, and they stood on their feet. Great fear fell on those who saw them.', pt: 'E depois daqueles três dias e meio o espírito de vida, vindo de Deus, entrou neles, e puseram-se sobre seus pés, e caiu grande temor sobre os que os viram.' },
      { v: 12, en: 'I heard a loud voice from heaven saying to them, “Come up here!” They went up into heaven in the cloud, and their enemies saw them.', pt: 'E ouviram uma grande voz do céu, que lhes dizia: Subi para cá. E subiram ao céu em uma nuvem; e os seus inimigos os viram.' },
      { v: 13, en: 'In that day there was a great earthquake, and a tenth of the city fell. Seven thousand people were killed in the earthquake, and the rest were terrified, and gave glory to the God of heaven.', pt: 'E naquela hora houve um grande terremoto, e caiu a décima parte da cidade, e no terremoto foram mortos sete mil homens; e os demais ficaram atemorizados, e deram glória ao Deus do céu.' },
      { v: 14, en: 'The second woe is past. Behold, the third woe comes quickly.', pt: 'É passado o segundo ai; eis que cedo vem o terceiro.' },
      { v: 15, en: 'The seventh angel sounded, and great voices in heaven followed, saying, “The kingdom of the world has become the Kingdom of our Lord, and of his Christ. He will reign forever and ever!”', pt: 'E tocou o sétimo anjo a sua trombeta, e houve no céu grandes vozes, que diziam: O reino do mundo passou a ser de nosso Senhor e do seu Cristo, e ele reinará pelos séculos dos séculos.' },
      { v: 16, en: 'The twenty-four elders, who sit on their thrones before God’s throne, fell on their faces and worshiped God,', pt: 'E os vinte e quatro anciãos, que estão assentados em seus tronos diante de Deus, prostraram-se sobre seus rostos e adoraram a Deus,' },
      { v: 17, en: 'saying: “We give you thanks, Lord God, the Almighty, the one who is and who was ; because you have taken your great power, and reigned.', pt: 'dizendo: Graças te damos, Senhor Deus Todo-Poderoso, que és, e que eras, porque tens tomado o teu grande poder, e começaste a reinar.' },
      { v: 18, en: 'The nations were angry, and your wrath came, as did the time for the dead to be judged, and to give your bondservants the prophets, their reward, as well as to the saints, and those who fear your name, to the small and the great; and to destroy those who destroy the earth.”', pt: 'Iraram-se, na verdade, as nações; então veio a tua ira, e o tempo de serem julgados os mortos, e o tempo de dares recompensa aos teus servos, os profetas, e aos santos, e aos que temem o teu nome, a pequenos e a grandes, e o tempo de destruíres os que destroem a terra.' },
      { v: 19, en: 'God’s temple that is in heaven was opened, and the ark of the Lord’s covenant was seen in his temple. Lightnings, sounds, thunders, an earthquake, and great hail followed.', pt: 'Abriu-se o santuário de Deus que está no céu, e no seu santuário foi vista a arca do seu pacto; e houve relâmpagos, vozes e trovões, e terremoto e grande saraivada.' },
    ],
    12: [
      { v: 1, en: 'A great sign was seen in heaven: a woman clothed with the sun, and the moon under her feet, and on her head a crown of twelve stars.', pt: 'E viu-se um grande sinal no céu: uma mulher vestida do sol, tendo a lua debaixo dos seus pés, e uma coroa de doze estrelas sobre a sua cabeça.' },
      { v: 2, en: 'She was with child. She cried out in pain, laboring to give birth.', pt: 'E estando grávida, gritava com as dores do parto, sofrendo tormentos para dar à luz.' },
      { v: 3, en: 'Another sign was seen in heaven. Behold, a great red dragon, having seven heads and ten horns, and on his heads seven crowns.', pt: 'Viu-se também outro sinal no céu: eis um grande dragão vermelho que tinha sete cabeças e dez chifres, e sobre as suas cabeças sete diademas;' },
      { v: 4, en: 'His tail drew one third of the stars of the sky, and threw them to the earth. The dragon stood before the woman who was about to give birth, so that when she gave birth he might devour her child.', pt: 'a sua cauda levava após si a terça parte das estrelas do céu, e lançou-as sobre a terra; e o dragão parou diante da mulher que estava para dar à luz, para que, dando ela à luz, lhe devorasse o filho.' },
      { v: 5, en: 'She gave birth to a son, a male child, who is to rule all the nations with a rod of iron. Her child was caught up to God, and to his throne.', pt: 'E deu à luz um filho, um varão que há de reger todas as nações com vara de ferro; e o seu filho foi arrebatado para Deus e para o seu trono.' },
      { v: 6, en: 'The woman fled into the wilderness, where she has a place prepared by God, that there they may nourish her one thousand two hundred sixty days.', pt: 'E a mulher fugiu para o deserto, onde já tinha lugar preparado por Deus, para que ali fosse alimentada durante mil duzentos e sessenta dias.' },
      { v: 7, en: 'There was war in the sky. Michael and his angels made war on the dragon. The dragon and his angels made war.', pt: 'Então houve guerra no céu: Miguel e os seus anjos batalhavam contra o dragão. E o dragão e os seus anjos batalhavam,' },
      { v: 8, en: 'They didn’t prevail, neither was a place found for them any more in heaven.', pt: 'mas não prevaleceram, nem mais o seu lugar se achou no céu.' },
      { v: 9, en: 'The great dragon was thrown down, the old serpent, he who is called the devil and Satan, the deceiver of the whole world. He was thrown down to the earth, and his angels were thrown down with him.', pt: 'E foi precipitado o grande dragão, a antiga serpente, que se chama o Diabo e Satanás, que engana todo o mundo; foi precipitado na terra, e os seus anjos foram precipitados com ele.' },
      { v: 10, en: 'I heard a loud voice in heaven, saying, “Now the salvation, the power, and the Kingdom of our God, and the authority of his Christ has come; for the accuser of our brothers has been thrown down, who accuses them before our God day and night.', pt: 'Então, ouvi uma grande voz no céu, que dizia: Agora é chegada a salvação, e o poder, e o reino do nosso Deus, e a autoridade do seu Cristo; porque já foi lançado fora o acusador de nossos irmãos, o qual diante do nosso Deus os acusava dia e noite.' },
      { v: 11, en: 'They overcame him because of the Lamb’s blood, and because of the word of their testimony. They didn’t love their life, even to death.', pt: 'E eles o venceram pelo sangue do Cordeiro e pela palavra do seu testemunho; e não amaram as suas vidas até a morte.' },
      { v: 12, en: 'Therefore rejoice, heavens, and you who dwell in them. Woe to the earth and to the sea, because the devil has gone down to you, having great wrath, knowing that he has but a short time.”', pt: 'Pelo que alegrai-vos, ó céus, e vós que neles habitais. Mas ai da terra e do mar! porque o Diabo desceu a vós com grande ira, sabendo que pouco tempo lhe resta.' },
      { v: 13, en: 'When the dragon saw that he was thrown down to the earth, he persecuted the woman who gave birth to the male child.', pt: 'Quando o dragão se viu precipitado na terra, perseguiu a mulher que dera à luz o filho varão.' },
      { v: 14, en: 'Two wings of the great eagle were given to the woman, that she might fly into the wilderness to her place, so that she might be nourished for a time, and times, and half a time, from the face of the serpent.', pt: 'E foram dadas à mulher as duas asas da grande águia, para que voasse para o deserto, ao seu lugar, onde é sustentada por um tempo, e tempos, e metade de um tempo, fora da vista da serpente.' },
      { v: 15, en: 'The serpent spewed water out of his mouth after the woman like a river, that he might cause her to be carried away by the stream.', pt: 'E a serpente lançou da sua boca, atrás da mulher, água como um rio, para fazer que ela fosse arrebatada pela corrente.' },
      { v: 16, en: 'The earth helped the woman, and the earth opened its mouth and swallowed up the river which the dragon spewed out of his mouth.', pt: 'A terra, porém acudiu à mulher; e a terra abriu a boca, e tragou o rio que o dragão lançara da sua boca.' },
      { v: 17, en: 'The dragon grew angry with the woman, and went away to make war with the rest of her offspring, who keep God’s commandments and hold Jesus’ testimony.', pt: 'E o dragão irou-se contra a mulher, e foi fazer guerra aos demais filhos dela, os que guardam os mandamentos de Deus, e mantêm o testemunho de Jesus.' },
      { v: 18, en: 'E o dragão parou sobre a areia do mar.', pt: 'E o dragão parou sobre a areia do mar.' },
    ],
    13: [
      { v: 1, en: 'Then I stood on the sand of the sea. I saw a beast coming up out of the sea, having ten horns and seven heads. On his horns were ten crowns, and on his heads, blasphemous names.', pt: 'Então vi subir do mar uma besta que tinha dez chifres e sete cabeças, e sobre os seus chifres dez diademas, e sobre as suas cabeças nomes de blasfêmia.' },
      { v: 2, en: 'The beast which I saw was like a leopard, and his feet were like those of a bear, and his mouth like the mouth of a lion. The dragon gave him his power, his throne, and great authority.', pt: 'E a besta que vi era semelhante ao leopardo, e os seus pés como os de urso, e a sua boca como a de leão; e o dragão deu-lhe o seu poder e o seu trono e grande autoridade.' },
      { v: 3, en: 'One of his heads looked like it had been wounded fatally. His fatal wound was healed, and the whole earth marveled at the beast.', pt: 'Também vi uma de suas cabeças como se fora ferida de morte, mas a sua ferida mortal foi curada. Toda a terra se maravilhou, seguindo a besta,' },
      { v: 4, en: 'They worshiped the dragon, because he gave his authority to the beast, and they worshiped the beast, saying, “Who is like the beast? Who is able to make war with him?”', pt: 'e adoraram o dragão, porque deu à besta a sua autoridade; e adoraram a besta, dizendo: Quem é semelhante à besta? quem poderá batalhar contra ela?' },
      { v: 5, en: 'A mouth speaking great things and blasphemy was given to him. Authority to make war for forty-two months was given to him.', pt: 'Foi-lhe dada uma boca que proferia arrogâncias e blasfêmias; e deu-se-lhe autoridade para atuar por quarenta e dois meses.' },
      { v: 6, en: 'He opened his mouth for blasphemy against God, to blaspheme his name, and his dwelling, those who dwell in heaven.', pt: 'E abriu a boca em blasfêmias contra Deus, para blasfemar do seu nome e do seu tabernáculo e dos que habitam no céu.' },
      { v: 7, en: 'It was given to him to make war with the saints, and to overcome them. Authority over every tribe, people, language, and nation was given to him.', pt: 'Também lhe foi permitido fazer guerra aos santos, e vencê-los; e deu-se-lhe autoridade sobre toda tribo, e povo, e língua e nação.' },
      { v: 8, en: 'All who dwell on the earth will worship him, everyone whose name has not been written from the foundation of the world in the book of life of the Lamb who has been killed.', pt: 'E adora-la-ão todos os que habitam sobre a terra, esses cujos nomes não estão escritos no livro do Cordeiro que foi morto desde a fundação do mundo.' },
      { v: 9, en: 'If anyone has an ear, let him hear.', pt: 'Se alguém tem ouvidos, ouça.' },
      { v: 10, en: 'If anyone is to go into captivity, he will go into captivity. If anyone is to be killed with the sword, he must be killed. Here is the endurance and the faith of the saints.', pt: 'Se alguém leva em cativeiro, em cativeiro irá; se alguém matar à espada, necessário é que à espada seja morto. Aqui está a perseverança e a fé dos santos.' },
      { v: 11, en: 'I saw another beast coming up out of the earth. He had two horns like a lamb, and he spoke like a dragon.', pt: 'E vi subir da terra outra besta, e tinha dois chifres semelhantes aos de um cordeiro; e falava como dragão.' },
      { v: 12, en: 'He exercises all the authority of the first beast in his presence. He makes the earth and those who dwell in it to worship the first beast, whose fatal wound was healed.', pt: 'Também exercia toda a autoridade da primeira besta na sua presença; e fazia que a terra e os que nela habitavam adorassem a primeira besta, cuja ferida mortal fora curada.' },
      { v: 13, en: 'He performs great signs, even making fire come down out of the sky to the earth in the sight of people.', pt: 'E operava grandes sinais, de maneira que fazia até descer fogo do céu à terra, à vista dos homens;' },
      { v: 14, en: 'He deceives my own people who dwell on the earth because of the signs he was granted to do in front of the beast; saying to those who dwell on the earth, that they should make an image to the beast who had the sword wound and lived.', pt: 'e, por meio dos sinais que lhe foi permitido fazer na presença da besta, enganava os que habitavam sobre a terra e lhes dizia que fizessem uma imagem à besta que recebera a ferida da espada e vivia.' },
      { v: 15, en: 'It was given to him to give breath to it, to the image of the beast, that the image of the beast should both speak, and cause as many as wouldn’t worship the image of the beast to be killed.', pt: 'Foi-lhe concedido também dar fôlego à imagem da besta, para que a imagem da besta falasse, e fizesse que fossem mortos todos os que não adorassem a imagem da besta.' },
      { v: 16, en: 'He causes all, the small and the great, the rich and the poor, and the free and the slave, to be given marks on their right hands, or on their foreheads;', pt: 'E fez que a todos, pequenos e grandes, ricos e pobres, livres e escravos, lhes fosse posto um sinal na mão direita, ou na fronte,' },
      { v: 17, en: 'and that no one would be able to buy or to sell, unless he has that mark, the name of the beast or the number of his name.', pt: 'para que ninguém pudesse comprar ou vender, senão aquele que tivesse o sinal, ou o nome da besta, ou o número do seu nome.' },
      { v: 18, en: 'Here is wisdom. He who has understanding, let him calculate the number of the beast, for it is the number of a man. His number is six hundred sixty-six.', pt: 'Aqui há sabedoria. Aquele que tem entendimento, calcule o número da besta; porque é o número de um homem, e o seu número é seiscentos e sessenta e seis.' },
    ],
    14: [
      { v: 1, en: 'I saw, and behold, the Lamb standing on Mount Zion, and with him a number, one hundred forty-four thousand, having his name, and the name of his Father, written on their foreheads.', pt: 'E olhei, e eis o Cordeiro em pé sobre o Monte Sião, e com ele cento e quarenta e quatro mil, que traziam na fronte escrito o nome dele e o nome de seu Pai.' },
      { v: 2, en: 'I heard a sound from heaven, like the sound of many waters, and like the sound of a great thunder. The sound which I heard was like that of harpists playing on their harps.', pt: 'E ouvi uma voz do céu, como a voz de muitas águas, e como a voz de um grande trovão e a voz que ouvi era como de harpistas, que tocavam as suas harpas.' },
      { v: 3, en: 'They sing a new song before the throne, and before the four living creatures and the elders. No one could learn the song except the one hundred forty-four thousand, those who had been redeemed out of the earth.', pt: 'E cantavam um cântico novo diante do trono, e diante dos quatro seres viventes e dos anciãos; e ninguém podia aprender aquele cântico, senão os cento e quarenta e quatro mil, aqueles que foram comprados da terra.' },
      { v: 4, en: 'These are those who were not defiled with women, for they are virgins. These are those who follow the Lamb wherever he goes. These were redeemed by Jesus from among men, the first fruits to God and to the Lamb.', pt: 'Estes são os que não se contaminaram com mulheres; porque são virgens. Estes são os que seguem o Cordeiro para onde quer que vá. Estes foram comprados dentre os homens para serem as primícias para Deus e para o Cordeiro.' },
      { v: 5, en: 'In their mouth was found no lie, for they are blameless.', pt: 'E na sua boca não se achou engano; porque são irrepreensíveis.' },
      { v: 6, en: 'I saw an angel flying in mid heaven, having an eternal Good News to proclaim to those who dwell on the earth, and to every nation, tribe, language, and people.', pt: 'E vi outro anjo voando pelo meio do céu, e tinha um evangelho eterno para proclamar aos que habitam sobre a terra e a toda nação, e tribo, e língua, e povo,' },
      { v: 7, en: 'He said with a loud voice, “Fear the Lord, and give him glory; for the hour of his judgment has come. Worship him who made the heaven, the earth, the sea, and the springs of waters!”', pt: 'dizendo com grande voz: Temei a Deus, e dai-lhe glória; porque é chegada a hora do seu juízo; e adorai aquele que fez o céu, e a terra, e o mar, e as fontes das águas.' },
      { v: 8, en: 'Another, a second angel, followed, saying, “Babylon the great has fallen, which has made all the nations to drink of the wine of the wrath of her sexual immorality.”', pt: 'Um segundo anjo o seguiu, dizendo: Caiu, caiu a grande Babilônia, que a todas as nações deu a beber do vinho da ira da sua prostituição.' },
      { v: 9, en: 'Another angel, a third, followed them, saying with a great voice, “If anyone worships the beast and his image, and receives a mark on his forehead, or on his hand,', pt: 'Seguiu-os ainda um terceiro anjo, dizendo com grande voz: Se alguém adorar a besta, e a sua imagem, e receber o sinal na fronte, ou na mão,' },
      { v: 10, en: 'he also will drink of the wine of the wrath of God, which is prepared unmixed in the cup of his anger. He will be tormented with fire and sulfur in the presence of the holy angels, and in the presence of the Lamb.', pt: 'também o tal beberá do vinho da ira de Deus, que se acha preparado sem mistura, no cálice da sua ira; e será atormentado com fogo e enxofre diante dos santos anjos e diante do Cordeiro.' },
      { v: 11, en: 'The smoke of their torment goes up forever and ever. They have no rest day and night, those who worship the beast and his image, and whoever receives the mark of his name.', pt: 'A fumaça do seu tormento sobe para todo o sempre; e não têm repouso nem de dia nem de noite os que adoram a besta e a sua imagem, nem aquele que recebe o sinal do seu nome.' },
      { v: 12, en: 'Here is the perseverance of the saints, those who keep the commandments of God, and the faith of Jesus.”', pt: 'Aqui está a perseverança dos santos, daqueles que guardam os mandamentos de Deus e a fé em Jesus.' },
      { v: 13, en: 'I heard a voice from heaven saying, “Write, ‘Blessed are the dead who die in the Lord from now on.’” “Yes,” says the Spirit, “that they may rest from their labors; for their works follow with them.”', pt: 'Então ouvi uma voz do céu, que dizia: Escreve: Bem-aventurados os mortos que desde agora morrem no Senhor. Sim, diz o Espírito, para que descansem dos seus trabalhos, pois as suas obras os acompanham.' },
      { v: 14, en: 'I looked, and behold, a white cloud; and on the cloud one sitting like a son of man, having on his head a golden crown, and in his hand a sharp sickle.', pt: 'E olhei, e eis uma nuvem branca, e assentado sobre a nuvem um semelhante a filho de homem, que tinha sobre a cabeça uma coroa de ouro, e na mão uma foice afiada.' },
      { v: 15, en: 'Another angel came out of the temple, crying with a loud voice to him who sat on the cloud, “Send your sickle, and reap; for the hour to reap has come; for the harvest of the earth is ripe!”', pt: 'E outro anjo saiu do santuário, clamando com grande voz ao que estava assentado sobre a nuvem: Lança a tua foice e ceifa, porque é chegada a hora de ceifar, porque já a seara da terra está madura.' },
      { v: 16, en: 'He who sat on the cloud thrust his sickle on the earth, and the earth was reaped.', pt: 'Então aquele que estava assentado sobre a nuvem meteu a sua foice à terra, e a terra foi ceifada.' },
      { v: 17, en: 'Another angel came out of the temple which is in heaven. He also had a sharp sickle.', pt: 'Ainda outro anjo saiu do santuário que está no céu, o qual também tinha uma foice afiada.' },
      { v: 18, en: 'Another angel came out from the altar, he who has power over fire, and he called with a great voice to him who had the sharp sickle, saying, “Send your sharp sickle, and gather the clusters of the vine of the earth, for the earth’s grapes are fully ripe!”', pt: 'E saiu do altar outro anjo, que tinha poder sobre o fogo, e clamou com grande voz ao que tinha a foice afiada, dizendo: Lança a tua foice afiada, e vindima os cachos da vinha da terra, porque já as suas uvas estão maduras.' },
      { v: 19, en: 'The angel thrust his sickle into the earth, and gathered the vintage of the earth, and threw it into the great wine press of the wrath of God.', pt: 'E o anjo meteu a sua foice à terra, e vindimou as uvas da vinha da terra, e lançou-as no grande lagar da ira de Deus.' },
      { v: 20, en: 'The wine press was trodden outside of the city, and blood came out of the wine press, even to the bridles of the horses, as far as one thousand six hundred stadia.', pt: 'E o lagar foi pisado fora da cidade, e saiu sangue do lagar até os freios dos cavalos, pelo espaço de mil e seiscentos estádios.' },
    ],
    15: [
      { v: 1, en: 'I saw another great and marvelous sign in the sky: seven angels having the seven last plagues, for in them God’s wrath is finished.', pt: 'Vi no céu ainda outro sinal, grande e admirável: sete anjos, que tinham as sete últimas pragas; porque nelas é consumada a ira de Deus.' },
      { v: 2, en: 'I saw something like a sea of glass mixed with fire, and those who overcame the beast, his image, and the number of his name, standing on the sea of glass, having harps of God.', pt: 'E vi como que um mar de vidro misturado com fogo; e os que tinham vencido a besta e a sua imagem e o número do seu nome estavam em pé junto ao mar de vidro, e tinham harpas de Deus.' },
      { v: 3, en: 'They sang the song of Moses, the servant of God, and the song of the Lamb, saying, “Great and marvelous are your works, Lord God, the Almighty! Righteous and true are your ways, you King of the nations.', pt: 'E cantavam o cântico de Moisés, servo de Deus, e o cântico do Cordeiro, dizendo: Grandes e admiráveis são as tuas obras, ó Senhor Deus Todo-Poderoso; justos e verdadeiros são os teus caminhos, ó Rei dos séculos.' },
      { v: 4, en: 'Who wouldn’t fear you, Lord, and glorify your name? For you only are holy. For all the nations will come and worship before you. For your righteous acts have been revealed.”', pt: 'Quem não te temerá, Senhor, e não glorificará o teu nome? Pois só tu és santo; por isso todas as nações virão e se prostrarão diante de ti, porque os teus juízos são manifestos.' },
      { v: 5, en: 'After these things I looked, and the temple of the tabernacle of the testimony in heaven was opened.', pt: 'Depois disto olhei, e abriu-se o santuário do tabernáculo do testemunho no céu;' },
      { v: 6, en: 'The seven angels who had the seven plagues came out, clothed with pure, bright linen, and wearing golden sashes around their breasts.', pt: 'e saíram do santuário os sete anjos que tinham as sete pragas, vestidos de linho puro e resplandecente, e cingidos, à altura do peito com cintos de ouro.' },
      { v: 7, en: 'One of the four living creatures gave to the seven angels seven golden bowls full of the wrath of God, who lives forever and ever.', pt: 'Um dos quatro seres viventes deu aos sete anjos sete taças de ouro, cheias da ira do Deus que vive pelos séculos dos séculos.' },
      { v: 8, en: 'The temple was filled with smoke from the glory of God, and from his power. No one was able to enter into the temple, until the seven plagues of the seven angels would be finished.', pt: 'E o santuário se encheu de fumaça pela glória de Deus e pelo seu poder; e ninguém podia entrar no santuário, enquanto não se consumassem as sete pragas dos sete anjos.' },
    ],
    16: [
      { v: 1, en: 'I heard a loud voice out of the temple, saying to the seven angels, “Go and pour out the seven bowls of the wrath of God on the earth!”', pt: 'E ouvi, vinda do santuário, uma grande voz, que dizia aos sete anjos: Ide e derramai sobre a terra as sete taças, da ira de Deus.' },
      { v: 2, en: 'The first went, and poured out his bowl into the earth, and it became a harmful and evil sore on the people who had the mark of the beast, and who worshiped his image.', pt: 'Então foi o primeiro e derramou a sua taça sobre a terra; e apareceu uma chaga ruim e maligna nos homens que tinham o sinal da besta e que adoravam a sua imagem.' },
      { v: 3, en: 'The second angel poured out his bowl into the sea, and it became blood as of a dead man. Every living thing in the sea died.', pt: 'O segundo anjo derramou a sua taça no mar, que se tornou em sangue como de um morto, e morreu todo ser vivente que estava no mar.' },
      { v: 4, en: 'The third poured out his bowl into the rivers and springs of water, and they became blood.', pt: 'O terceiro anjo derramou a sua taça nos rios e nas fontes das águas, e se tornaram em sangue.' },
      { v: 5, en: 'I heard the angel of the waters saying, “You are righteous, who are and who were, O Holy One, because you have judged these things.', pt: 'E ouvi o anjo das águas dizer: Justo és tu, que és e que eras, o Santo; porque julgaste estas coisas;' },
      { v: 6, en: 'For they poured out the blood of the saints and prophets, and you have given them blood to drink. They deserve this.”', pt: 'porque derramaram o sangue de santos e de profetas, e tu lhes tens dado sangue a beber; eles o merecem.' },
      { v: 7, en: 'I heard the altar saying, “Yes, Lord God, the Almighty, true and righteous are your judgments.”', pt: 'E ouvi uma voz do altar, que dizia: Na verdade, ó Senhor Deus Todo-Poderoso, verdadeiros e justos são os teus juízos.' },
      { v: 8, en: 'The fourth poured out his bowl on the sun, and it was given to him to scorch men with fire.', pt: 'O quarto anjo derramou a sua taça sobre o sol, e foi-lhe permitido que abrasasse os homens com fogo.' },
      { v: 9, en: 'People were scorched with great heat, and people blasphemed the name of God who has the power over these plagues. They didn’t repent and give him glory.', pt: 'E os homens foram abrasados com grande calor; e blasfemaram o nome de Deus, que tem poder sobre estas pragas; e não se arrependeram para lhe darem glória.' },
      { v: 10, en: 'The fifth poured out his bowl on the throne of the beast, and his kingdom was darkened. They gnawed their tongues because of the pain,', pt: 'O quinto anjo derramou a sua taça sobre o trono da besta, e o seu reino se fez tenebroso; e os homens mordiam de dor as suas línguas.' },
      { v: 11, en: 'and they blasphemed the God of heaven because of their pains and their sores. They didn’t repent of their works.', pt: 'E por causa das suas dores, e por causa das suas chagas, blasfemaram o Deus do céu; e não se arrependeram das suas obras.' },
      { v: 12, en: 'The sixth poured out his bowl on the great river, the Euphrates. Its water was dried up, that the way might be prepared for the kings that come from the sunrise.', pt: 'O sexto anjo derramou a sua taça sobre o grande rio Eufrates; e a sua água secou-se, para que se preparasse o caminho dos reis que vêm do oriente.' },
      { v: 13, en: 'I saw coming out of the mouth of the dragon, and out of the mouth of the beast, and out of the mouth of the false prophet, three unclean spirits, something like frogs;', pt: 'E da boca do dragão, e da boca da besta, e da boca do falso profeta, vi saírem três espíritos imundos, semelhantes a rãs.' },
      { v: 14, en: 'for they are spirits of demons, performing signs; which go out to the kings of the whole inhabited earth, to gather them together for the war of that great day of God, the Almighty.', pt: 'Pois são espíritos de demônios, que operam sinais; os quais vão ao encontro dos reis de todo o mundo, para os congregar para a batalha do grande dia do Deus Todo-Poderoso.' },
      { v: 15, en: '“Behold, I come like a thief. Blessed is he who watches, and keeps his clothes, so that he doesn’t walk naked, and they see his shame.”', pt: '(Eis que venho como ladrão. Bem-aventurado aquele que vigia, e guarda as suas vestes, para que não ande nu, e não se veja a sua nudez.)' },
      { v: 16, en: 'He gathered them together into the place which is called in Hebrew, Megiddo.', pt: 'E eles os congregaram no lugar que em hebraico se chama Armagedom.' },
      { v: 17, en: 'The seventh poured out his bowl into the air. A loud voice came out of the temple of heaven, from the throne, saying, “It is done!”', pt: 'O sétimo anjo derramou a sua taça no ar; e saiu uma grande voz do santuário, da parte do trono, dizendo: Está feito.' },
      { v: 18, en: 'There were lightnings, sounds, and thunders; and there was a great earthquake, such as was not since there were men on the earth, so great an earthquake, so mighty.', pt: 'E houve relâmpagos e vozes e trovões; houve também um grande terremoto, qual nunca houvera desde que há homens sobre a terra, terremoto tão forte quão grande;' },
      { v: 19, en: 'The great city was divided into three parts, and the cities of the nations fell. Babylon the great was remembered in the sight of God, to give to her the cup of the wine of the fierceness of his wrath.', pt: 'e a grande cidade fendeu-se em três partes, e as cidades das nações caíram; e Deus lembrou-se da grande Babilônia, para lhe dar o cálice do vinho do furor da sua ira.' },
      { v: 20, en: 'Every island fled away, and the mountains were not found.', pt: 'Todas ilhas fugiram, e os montes não mais se acharam.' },
      { v: 21, en: 'Great hailstones, about the weight of a talent, came down out of the sky on people. People blasphemed God because of the plague of the hail, for this plague is exceedingly severe.', pt: 'E sobre os homens caiu do céu uma grande saraivada, pedras quase do peso de um talento; e os homens blasfemaram de Deus por causa da praga da saraivada; porque a sua praga era mui grande.' },
    ],
    17: [
      { v: 1, en: 'One of the seven angels who had the seven bowls came and spoke with me, saying, “Come here. I will show you the judgment of the great prostitute who sits on many waters,', pt: 'Veio um dos sete anjos que tinham as sete taças, e falou comigo, dizendo: Vem, mostrar-te-ei a condenação da grande prostituta que está assentada sobre muitas águas;' },
      { v: 2, en: 'with whom the kings of the earth committed sexual immorality; and those who dwell in the earth were made drunken with the wine of her sexual immorality.”', pt: 'com a qual se prostituíram os reis da terra; e os que habitam sobre a terra se embriagaram com o vinho da sua prostituição.' },
      { v: 3, en: 'He carried me away in the Spirit into a wilderness. I saw a woman sitting on a scarlet-colored beast, full of blasphemous names, having seven heads and ten horns.', pt: 'Então ele me levou em espírito a um deserto; e vi uma mulher montada numa besta cor de escarlata, que estava cheia de nomes de blasfêmia, e que tinha sete cabeças e dez chifres.' },
      { v: 4, en: 'The woman was dressed in purple and scarlet, and decked with gold and precious stones and pearls, having in her hand a golden cup full of abominations and the impurities of the sexual immorality of the earth.', pt: 'A mulher estava vestida de púrpura e de escarlata, e adornada de ouro, pedras preciosas e pérolas; e tinha na mão um cálice de ouro, cheio das abominações, e da imundícia da prostituição;' },
      { v: 5, en: 'And on her forehead a name was written, “MYSTERY, BABYLON THE GREAT, THE MOTHER OF THE PROSTITUTES AND OF THE ABOMINATIONS OF THE EARTH.”', pt: 'e na sua fronte estava escrito um nome simbólico: A grande Babilônia, a mãe das prostituições e das abominações da terra.' },
      { v: 6, en: 'I saw the woman drunken with the blood of the saints, and with the blood of the martyrs of Jesus. When I saw her, I wondered with great amazement.', pt: 'E vi que a mulher estava embriagada com o sangue dos santos e com o sangue dos mártires de Jesus. Quando a vi, maravilhei-me com grande admiração.' },
      { v: 7, en: 'The angel said to me, “Why do you wonder? I will tell you the mystery of the woman, and of the beast that carries her, which has the seven heads and the ten horns.', pt: 'Ao que o anjo me disse: Por que te admiraste? Eu te direi o mistério da mulher, e da besta que a leva, a qual tem sete cabeças e dez chifres.' },
      { v: 8, en: 'The beast that you saw was, and is not; and is about to come up out of the abyss and to go into destruction. Those who dwell on the earth and whose names have not been written in the book of life from the foundation of the world will marvel when they see that the beast was, and is not, and shall be present.', pt: 'A besta que viste era e já não é; todavia está para subir do abismo, e vai-se para a perdição; e os que habitam sobre a terra e cujos nomes não estão escritos no livro da vida desde a fundação do mundo se admirarão, quando virem a besta que era e já não é, e que tornará a vir.' },
      { v: 9, en: 'Here is the mind that has wisdom. The seven heads are seven mountains on which the woman sits.', pt: 'Aqui está a mente que tem sabedoria. As sete cabeças são sete montes, sobre os quais a mulher está assentada;' },
      { v: 10, en: 'They are seven kings. Five have fallen, the one is, the other has not yet come. When he comes, he must continue a little while.', pt: 'são também sete reis: cinco já caíram; um existe; e o outro ainda não é vindo; e quando vier, deve permanecer pouco tempo.' },
      { v: 11, en: 'The beast that was, and is not, is himself also an eighth, and is of the seven; and he goes to destruction.', pt: 'A besta que era e já não é, é também o oitavo rei, e é dos sete, e vai-se para a perdição.' },
      { v: 12, en: 'The ten horns that you saw are ten kings who have received no kingdom as yet, but they receive authority as kings, with the beast, for one hour.', pt: 'Os dez chifres que viste são dez reis, os quais ainda não receberam o reino, mas receberão autoridade, como reis, por uma hora, juntamente com a besta.' },
      { v: 13, en: 'These have one mind, and they give their power and authority to the beast.', pt: 'Estes têm um mesmo intento, e entregarão o seu poder e autoridade à besta.' },
      { v: 14, en: 'These will war against the Lamb, and the Lamb will overcome them, for he is Lord of lords, and King of kings, and those who are with him are called chosen and faithful.”', pt: 'Estes combaterão contra o Cordeiro, e o Cordeiro os vencerá, porque é o Senhor dos senhores e o Rei dos reis; vencerão também os que estão com ele, os chamados, e eleitos, e fiéis.' },
      { v: 15, en: 'He said to me, “The waters which you saw, where the prostitute sits, are peoples, multitudes, nations, and languages.', pt: 'Disse-me ainda: As águas que viste, onde se assenta a prostituta, são povos, multidões, nações e línguas.' },
      { v: 16, en: 'The ten horns which you saw, and the beast, these will hate the prostitute, will make her desolate, will strip her naked, will eat her flesh, and will burn her utterly with fire.', pt: 'E os dez chifres que viste, e a besta, estes odiarão a prostituta e a tornarão desolada e nua, e comerão as suas carnes, e a queimarão no fogo.' },
      { v: 17, en: 'For God has put in their hearts to do what he has in mind, to be of one mind, and to give their kingdom to the beast, until the words of God should be accomplished.', pt: 'Porque Deus lhes pôs nos corações o executarem o intento dele, chegarem a um acordo, e entregarem à besta o seu reino, até que se cumpram as palavras de Deus.' },
      { v: 18, en: 'The woman whom you saw is the great city, which reigns over the kings of the earth.”', pt: 'E a mulher que viste é a grande cidade que reina sobre os reis da terra.' },
    ],
    18: [
      { v: 1, en: 'After these things, I saw another angel coming down out of the sky, having great authority. The earth was illuminated with his glory.', pt: 'Depois destas coisas vi descer do céu outro anjo que tinha grande autoridade, e a terra foi iluminada com a sua glória.' },
      { v: 2, en: 'He cried with a mighty voice, saying, “Fallen, fallen is Babylon the great, and she has become a habitation of demons, a prison of every unclean spirit, and a prison of every unclean and hateful bird!', pt: 'E ele clamou com voz forte, dizendo: Caiu, caiu a grande Babilônia, e se tornou morada de demônios, e guarida de todo espírito imundo, e guarida de toda ave imunda e detestável.' },
      { v: 3, en: 'For all the nations have drunk of the wine of the wrath of her sexual immorality, the kings of the earth committed sexual immorality with her, and the merchants of the earth grew rich from the abundance of her luxury.”', pt: 'Porque todas as nações têm bebido do vinho da ira da sua prostituição, e os reis da terra se prostituíram com ela; e os mercadores da terra se enriqueceram com a abundância de suas delícias.' },
      { v: 4, en: 'I heard another voice from heaven, saying, “Come out of her, my people, that you have no participation in her sins, and that you don’t receive of her plagues,', pt: 'Ouvi outra voz do céu dizer: Sai dela, povo meu, para que não sejas participante dos sete pecados, e para que não incorras nas suas pragas.' },
      { v: 5, en: 'for her sins have reached to the sky, and God has remembered her iniquities.', pt: 'Porque os seus pecados se acumularam até o céu, e Deus se lembrou das iniqüidades dela.' },
      { v: 6, en: 'Return to her just as she returned, and repay her double as she did, and according to her works. In the cup which she mixed, mix to her double.', pt: 'Tornai a dar-lhe como também ela vos tem dado, e retribuí-lhe em dobro conforme as suas obras; no cálice em que vos deu de beber dai-lhe a ela em dobro.' },
      { v: 7, en: 'However much she glorified herself, and grew wanton, so much give her of torment and mourning. For she says in her heart, ‘I sit a queen, and am no widow, and will in no way see mourning.’', pt: 'Quanto ela se glorificou, e em delícias esteve, tanto lhe dai de tormento e de pranto; pois que ela diz em seu coração: Estou assentada como rainha, e não sou viúva, e de modo algum verei o pranto.' },
      { v: 8, en: 'Therefore in one day her plagues will come: death, mourning, and famine; and she will be utterly burned with fire; for the Lord God who has judged her is strong.', pt: 'Por isso, num mesmo dia virão as suas pragas, a morte, e o pranto, e a fome; e será consumida no fogo; porque forte é o Senhor Deus que a julga.' },
      { v: 9, en: 'The kings of the earth, who committed sexual immorality and lived wantonly with her, will weep and wail over her, when they look at the smoke of her burning,', pt: 'E os reis da terra, que com ela se prostituíram e viveram em delícias, sobre ela chorarão e prantearão, quando virem a fumaça do seu incêndio;' },
      { v: 10, en: 'standing far away for the fear of her torment, saying, ‘Woe, woe, the great city, Babylon, the strong city! For your judgment has come in one hour.’', pt: 'e, estando de longe por medo do tormento dela, dirão: Ai! ai da grande cidade, Babilônia, a cidade forte! pois numa só hora veio o teu julgamento.' },
      { v: 11, en: 'The merchants of the earth weep and mourn over her, for no one buys their merchandise any more;', pt: 'E sobre ela choram e lamentam os mercadores da terra; porque ninguém compra mais as suas mercadorias:' },
      { v: 12, en: 'merchandise of gold, silver, precious stones, pearls, fine linen, purple, silk, scarlet, all expensive wood, every vessel of ivory, every vessel made of most precious wood, and of brass, and iron, and marble;', pt: 'mercadorias de ouro, de prata, de pedras preciosas, de pérolas, de linho fino, de púrpura, de seda e de escarlata; e toda espécie de madeira odorífera, e todo objeto de marfim, de madeira preciosíssima, de bronze, de ferro e de mármore;' },
      { v: 13, en: 'and cinnamon, incense, perfume, frankincense, wine, olive oil, fine flour, wheat, sheep, horses, chariots, and people’s bodies and souls.', pt: 'e canela, especiarias, perfume, mirra e incenso; e vinho, azeite, flor de farinha e trigo; e gado, ovelhas, cavalos e carros; e escravos, e até almas de homens.' },
      { v: 14, en: 'The fruits which your soul lusted after have been lost to you, and all things that were dainty and sumptuous have perished from you, and you will find them no more at all.', pt: 'Também os frutos que a tua alma cobiçava foram-se de ti; e todas as coisas delicadas e suntuosas se foram de ti, e nunca mais se acharão.' },
      { v: 15, en: 'The merchants of these things, who were made rich by her, will stand far away for the fear of her torment, weeping and mourning;', pt: 'Os mercadores destas coisas, que por ela se enriqueceram, ficarão de longe por medo do tormento dela, chorando e lamentando,' },
      { v: 16, en: 'saying, ‘Woe, woe, the great city, she who was dressed in fine linen, purple, and scarlet, and decked with gold and precious stones and pearls!', pt: 'dizendo: Ai! ai da grande cidade, da que estava vestida de linho fino, de púrpura, de escarlata, e adornada com ouro, e pedras preciosas, e pérolas! porque numa só hora foram assoladas tantas riquezas.' },
      { v: 17, en: 'For in an hour such great riches are made desolate.’ Every ship master, and everyone who sails anywhere, and mariners, and as many as gain their living by sea, stood far away,', pt: 'E todo piloto, e todo o que navega para qualquer porto e todos os marinheiros, e todos os que trabalham no mar se puseram de longe;' },
      { v: 18, en: 'and cried out as they looked at the smoke of her burning, saying, ‘What is like the great city?’', pt: 'e, contemplando a fumaça do incêndio dela, clamavam: Que cidade é semelhante a esta grande cidade?' },
      { v: 19, en: 'They cast dust on their heads, and cried, weeping and mourning, saying, ‘Woe, woe, the great city, in which all who had their ships in the sea were made rich by reason of her great wealth!’ For she is made desolate in one hour.', pt: 'E lançaram pó sobre as suas cabeças, e clamavam, chorando e lamentando, dizendo: Ai! ai da grande cidade, na qual todos os que tinham naus no mar se enriqueceram em razão da sua opulência! porque numa só hora foi assolada.' },
      { v: 20, en: '“Rejoice over her, O heaven, you saints, apostles, and prophets; for God has judged your judgment on her.”', pt: 'Exulta sobre ela, ó céu, e vós, santos e apóstolos e profetas; porque Deus vindicou a vossa causa contra ela.' },
      { v: 21, en: 'A mighty angel took up a stone like a great millstone and cast it into the sea, saying, “Thus with violence will Babylon, the great city, be thrown down, and will be found no more at all.', pt: 'Um forte anjo levantou uma pedra, qual uma grande mó, e lançou-a no mar, dizendo: Com igual ímpeto será lançada Babilônia, a grande cidade, e nunca mais será achada.' },
      { v: 22, en: 'The voice of harpists, minstrels, flute players, and trumpeters will be heard no more at all in you. No craftsman, of whatever craft, will be found any more at all in you. The sound of a mill will be heard no more at all in you.', pt: 'E em ti não se ouvirá mais o som de harpistas, de músicos, de flautistas e de trombeteiros; e nenhum artífice de arte alguma se achará mais em ti; e em ti não mais se ouvirá ruído de mó;' },
      { v: 23, en: 'The light of a lamp will shine no more at all in you. The voice of the bridegroom and of the bride will be heard no more at all in you; for your merchants were the princes of the earth; for with your sorcery all the nations were deceived.', pt: 'e luz de candeia não mais brilhará em ti, e voz de noivo e de noiva não mais em ti se ouvirá; porque os teus mercadores eram os grandes da terra; porque todas as nações foram enganadas pelas tuas feitiçarias.' },
      { v: 24, en: 'In her was found the blood of prophets and of saints, and of all who have been slain on the earth.”', pt: 'E nela se achou o sangue dos profetas, e dos santos, e de todos os que foram mortos na terra.' },
    ],
    19: [
      { v: 1, en: 'After these things I heard something like a loud voice of a great multitude in heaven, saying, “Hallelujah! Salvation, power, and glory belong to our God:', pt: 'Depois destas coisas, ouvi no céu como que uma grande voz de uma imensa multidão, que dizia: Aleluia! A salvação e a glória e o poder pertencem ao nosso Deus;' },
      { v: 2, en: 'for true and righteous are his judgments. For he has judged the great prostitute, who corrupted the earth with her sexual immorality, and he has avenged the blood of his servants at her hand.”', pt: 'porque verdadeiros e justos são os seus juízos, pois julgou a grande prostituta, que havia corrompido a terra com a sua prostituição, e das mãos dela vingou o sangue dos seus servos.' },
      { v: 3, en: 'A second said, “Hallelujah! Her smoke goes up forever and ever.”', pt: 'E outra vez disseram: Aleluia. E a fumaça dela sobe pelos séculos dos séculos.' },
      { v: 4, en: 'The twenty-four elders and the four living creatures fell down and worshiped God who sits on the throne, saying, “Amen! Hallelujah!”', pt: 'Então os vinte e quatro anciãos e os quatro seres viventes prostraram-se e adoraram a Deus que está assentado no trono, dizendo: Amém. Aleluia!' },
      { v: 5, en: 'A voice came from the throne, saying, “Give praise to our God, all you his servants, you who fear him, the small and the great!”', pt: 'E saiu do trono uma voz, dizendo: Louvai o nosso Deus, vós, todos os seus servos, e vós que o temeis, assim pequenos como grandes.' },
      { v: 6, en: 'I heard something like the voice of a great multitude, and like the voice of many waters, and like the voice of mighty thunders, saying, “Hallelujah! For the Lord our God, the Almighty, reigns!', pt: 'Também ouvi uma voz como a de grande multidão, como a voz de muitas águas, e como a voz de fortes trovões, que dizia: Aleluia! porque já reina o Senhor nosso Deus, o Todo-Poderoso.' },
      { v: 7, en: 'Let us rejoice and be exceedingly glad, and let us give the glory to him. For the marriage of the Lamb has come, and his wife has made herself ready.”', pt: 'Regozijemo-nos, e exultemos, e demos-lhe a glória; porque são chegadas as bodas do Cordeiro, e já a sua noiva se preparou,' },
      { v: 8, en: 'It was given to her that she would array herself in bright, pure, fine linen: for the fine linen is the righteous acts of the saints.', pt: 'e foi-lhe permitido vestir-se de linho fino, resplandecente e puro; pois o linho fino são as obras justas dos santos.' },
      { v: 9, en: 'He said to me, “Write, ‘Blessed are those who are invited to the marriage supper of the Lamb.’” He said to me, “These are true words of God.”', pt: 'E disse-me: Escreve: Bem-aventurados aqueles que são chamados à ceia das bodas do Cordeiro. Disse-me ainda: Estas são as verdadeiras palavras de Deus.' },
      { v: 10, en: 'I fell down before his feet to worship him. He said to me, “Look! Don’t do it! I am a fellow bondservant with you and with your brothers who hold the testimony of Jesus. Worship God, for the testimony of Jesus is the Spirit of Prophecy.”', pt: 'Então me lancei a seus pés para adorá-lo, mas ele me disse: Olha, não faças tal: sou conservo teu e de teus irmãos, que têm o testemunho de Jesus; adora a Deus; pois o testemunho de Jesus é o espírito da profecia.' },
      { v: 11, en: 'I saw the heaven opened, and behold, a white horse, and he who sat on it is called Faithful and True. In righteousness he judges and makes war.', pt: 'E vi o céu aberto, e eis um cavalo branco; e o que estava montado nele chama-se Fiel e Verdadeiro; e julga a peleja com justiça.' },
      { v: 12, en: 'His eyes are a flame of fire, and on his head are many crowns. He has names written and a name written which no one knows but he himself.', pt: 'Os seus olhos eram como chama de fogo; sobre a sua cabeça havia muitos diademas; e tinha um nome escrito, que ninguém sabia sabia senão ele mesmo.' },
      { v: 13, en: 'He is clothed in a garment sprinkled with blood. His name is called “The Word of God.”', pt: 'Estava vestido de um manto salpicado de sangue; e o nome pelo qual se chama é o Verbo de Deus.' },
      { v: 14, en: 'The armies which are in heaven followed him on white horses, clothed in white, pure, fine linen.', pt: 'Seguiam-no os exércitos que estão no céu, em cavalos brancos, e vestidos de linho fino, branco e puro.' },
      { v: 15, en: 'Out of his mouth proceeds a sharp, double-edged sword, that with it he should strike the nations. He will rule them with an iron rod. He treads the wine press of the fierceness of the wrath of God, the Almighty.', pt: 'Da sua boca saía uma espada afiada, para ferir com ela as nações; ele as regerá com vara de ferro; e ele mesmo é o que pisa o lagar do vinho do furor da ira do Deus Todo-Poderoso.' },
      { v: 16, en: 'He has on his garment and on his thigh a name written, “KING OF KINGS, AND LORD OF LORDS.”', pt: 'No manto, sobre a sua coxa tem escrito o nome: Rei dos reis e Senhor dos senhores.' },
      { v: 17, en: 'I saw an angel standing in the sun. He cried with a loud voice, saying to all the birds that fly in the sky, “Come! Be gathered together to the great supper of God,', pt: 'E vi um anjo em pé no sol; e clamou com grande voz, dizendo a todas as aves que voavam pelo meio do céu: Vinde, ajuntai-vos para a grande ceia de Deus,' },
      { v: 18, en: 'that you may eat the flesh of kings, the flesh of captains, the flesh of mighty men, and the flesh of horses and of those who sit on them, and the flesh of all men, both free and slave, small and great.”', pt: 'para comerdes carnes de reis, carnes de comandantes, carnes de poderosos, carnes de cavalos e dos que neles montavam, sim, carnes de todos os homens, livres e escravos, pequenos e grandes.' },
      { v: 19, en: 'I saw the beast, and the kings of the earth, and their armies, gathered together to make war against him who sat on the horse, and against his army.', pt: 'E vi a besta, e os reis da terra, e os seus exércitos reunidos para fazerem guerra àquele que estava montado no cavalo, e ao seu exército.' },
      { v: 20, en: 'The beast was taken, and with him the false prophet who worked the signs in his sight, with which he deceived those who had received the mark of the beast and those who worshiped his image. These two were thrown alive into the lake of fire that burns with sulfur.', pt: 'E a besta foi presa, e com ela o falso profeta que fizera diante dela os sinais com que enganou os que receberam o sinal da besta e os que adoraram a sua imagem. Estes dois foram lançados vivos no lago de fogo que arde com enxofre.' },
      { v: 21, en: 'The rest were killed with the sword of him who sat on the horse, the sword which came out of his mouth. All the birds were filled with their flesh.', pt: 'E os demais foram mortos pela espada que saía da boca daquele que estava montado no cavalo; e todas as aves se fartaram das carnes deles.' },
    ],
    20: [
      { v: 1, en: 'I saw an angel coming down out of heaven, having the key of the abyss and a great chain in his hand.', pt: 'E vi descer do céu um anjo, que tinha a chave do abismo e uma grande cadeia na sua mão.' },
      { v: 2, en: 'He seized the dragon, the old serpent, which is the devil and Satan, who deceives the whole inhabited earth, and bound him for a thousand years,', pt: 'Ele prendeu o dragão, a antiga serpente, que é o Diabo e Satanás, e o amarrou por mil anos.' },
      { v: 3, en: 'and cast him into the abyss, and shut it, and sealed it over him, that he should deceive the nations no more, until the thousand years were finished. After this, he must be freed for a short time.', pt: 'Lançou-o no abismo, o qual fechou e selou sobre ele, para que não enganasse mais as nações até que os mil anos se completassem. Depois disto é necessário que ele seja solto por um pouco de tempo.' },
      { v: 4, en: 'I saw thrones, and they sat on them, and judgment was given to them. I saw the souls of those who had been beheaded for the testimony of Jesus, and for the word of God, and such as didn’t worship the beast nor his image, and didn’t receive the mark on their forehead and on their hand. They lived and reigned with Christ for a thousand years.', pt: 'Então vi uns tronos; e aos que se assentaram sobre eles foi dado o poder de julgar; e vi as almas daqueles que foram degolados por causa do testemunho de Jesus e da palavra de Deus, e que não adoraram a besta nem a sua imagem, e não receberam o sinal na fronte nem nas mãos; e reviveram, e reinaram com Cristo durante mil anos.' },
      { v: 5, en: 'The rest of the dead didn’t live until the thousand years were finished. This is the first resurrection.', pt: 'Mas os outros mortos não reviveram, até que os mil anos se completassem. Esta é a primeira ressurreição.' },
      { v: 6, en: 'Blessed and holy is he who has part in the first resurrection. Over these, the second death has no power, but they will be priests of God and of Christ, and will reign with him one thousand years.', pt: 'Bem-aventurado e santo é aquele que tem parte na primeira ressurreição; sobre estes não tem poder a segunda morte; mas serão sacerdotes de Deus e de Cristo, e reinarão com ele durante os mil anos.' },
      { v: 7, en: 'And after the thousand years, Satan will be released from his prison,', pt: 'Ora, quando se completarem os mil anos, Satanás será solto da sua prisão,' },
      { v: 8, en: 'and he will come out to deceive the nations which are in the four corners of the earth, Gog and Magog, to gather them together to the war; the number of whom is as the sand of the sea.', pt: 'e sairá a enganar as nações que estão nos quatro cantos da terra, Gogue e Magogue, cujo número é como a areia do mar, a fim de ajuntá-las para a batalha.' },
      { v: 9, en: 'They went up over the width of the earth, and surrounded the camp of the saints, and the beloved city. Fire came down out of heaven from God and devoured them.', pt: 'E subiram sobre a largura da terra, e cercaram o arraial dos santos e a cidade querida; mas desceu fogo do céu, e os devorou;' },
      { v: 10, en: 'The devil who deceived them was thrown into the lake of fire and sulfur, where the beast and the false prophet are also. They will be tormented day and night forever and ever.', pt: 'e o Diabo, que os enganava, foi lançado no lago de fogo e enxofre, onde estão a besta e o falso profeta; e de dia e de noite serão atormentados pelos séculos dos séculos.' },
      { v: 11, en: 'I saw a great white throne, and him who sat on it, from whose face the earth and the heaven fled away. There was found no place for them.', pt: 'E vi um grande trono branco e o que estava assentado sobre ele, de cuja presença fugiram a terra e o céu; e não foi achado lugar para eles.' },
      { v: 12, en: 'I saw the dead, the great and the small, standing before the throne, and they opened books. Another book was opened, which is the book of life. The dead were judged out of the things which were written in the books, according to their works.', pt: 'E vi os mortos, grandes e pequenos, em pé diante do trono; e abriram-se uns livros; e abriu-se outro livro, que é o da vida; e os mortos foram julgados pelas coisas que estavam escritas nos livros, segundo as suas obras.' },
      { v: 13, en: 'The sea gave up the dead who were in it. Death and Hades gave up the dead who were in them. They were judged, each one according to his works.', pt: 'O mar entregou os mortos que nele havia; e a morte e o hades entregaram os mortos que neles havia; e foram julgados, cada um segundo as suas obras.' },
      { v: 14, en: 'Death and Hades were thrown into the lake of fire. This is the second death, the lake of fire.', pt: 'E a morte e o hades foram lançados no lago de fogo. Esta é a segunda morte, o lago de fogo.' },
      { v: 15, en: 'If anyone was not found written in the book of life, he was cast into the lake of fire.', pt: 'E todo aquele que não foi achado inscrito no livro da vida, foi lançado no lago de fogo.' },
    ],
    21: [
      { v: 1, en: 'I saw a new heaven and a new earth: for the first heaven and the first earth have passed away, and the sea is no more.', pt: 'E vi um novo céu e uma nova terra. Porque já se foram o primeiro céu e a primeira terra, e o mar já não existe.' },
      { v: 2, en: 'I saw the holy city, New Jerusalem, coming down out of heaven from God, prepared like a bride adorned for her husband.', pt: 'E vi a santa cidade, a nova Jerusalém, que descia do céu da parte de Deus, adereçada como uma noiva ataviada para o seu noivo.' },
      { v: 3, en: 'I heard a loud voice out of heaven saying, “Behold, God’s dwelling is with people, and he will dwell with them, and they will be his people, and God himself will be with them as their God.', pt: 'E ouvi uma grande voz, vinda do trono, que dizia: Eis que o tabernáculo de Deus está com os homens, pois com eles habitará, e eles serão o seu povo, e Deus mesmo estará com eles.' },
      { v: 4, en: 'He will wipe away every tear from their eyes. Death will be no more; neither will there be mourning, nor crying, nor pain, any more. The first things have passed away.”', pt: 'Ele enxugará de seus olhos toda lágrima; e não haverá mais morte, nem haverá mais pranto, nem lamento, nem dor; porque já as primeiras coisas são passadas.' },
      { v: 5, en: 'He who sits on the throne said, “Behold, I am making all things new.” He said, “Write, for these words of God are faithful and true.”', pt: 'E o que estava assentado sobre o trono disse: Eis que faço novas todas as coisas. E acrescentou: Escreve; porque estas palavras são fiéis e verdadeiras.' },
      { v: 6, en: 'He said to me, “I have become the Alpha and the Omega, the Beginning and the End. I will give freely to him who is thirsty from the spring of the water of life.', pt: 'Disse-me ainda: está cumprido: Eu sou o Alfa e o èmega, o princípio e o fim. A quem tiver sede, de graça lhe darei a beber da fonte da água da vida.' },
      { v: 7, en: 'He who overcomes, I will give him these things. I will be his God, and he will be my son.', pt: 'Aquele que vencer herdará estas coisas; e eu serei seu Deus, e ele será meu filho.' },
      { v: 8, en: 'But for the cowardly, unbelieving, sinners, abominable, murderers, sexually immoral, sorcerers, idolaters, and all liars, their part is in the lake that burns with fire and sulfur, which is the second death.”', pt: 'Mas, quanto aos medrosos, e aos incrédulos, e aos abomináveis, e aos homicidas, e aos adúlteros, e aos feiticeiros, e aos idólatras, e a todos os mentirosos, a sua parte será no lago ardente de fogo e enxofre, que é a segunda morte.' },
      { v: 9, en: 'One of the seven angels who had the seven bowls, who were loaded with the seven last plagues came, and he spoke with me, saying, “Come here. I will show you the wife, the Lamb’s bride.”', pt: 'E veio um dos sete anjos que tinham as sete taças cheias das sete últimas pragas, e falou comigo, dizendo: Vem, mostrar-te-ei a noiva, a esposa do Cordeiro.' },
      { v: 10, en: 'He carried me away in the Spirit to a great and high mountain, and showed me the holy city, Jerusalem, coming down out of heaven from God,', pt: 'E levou-me em espírito a um grande e alto monte, e mostrou- me a santa cidade de Jerusalém, que descia do céu da parte de Deus,' },
      { v: 11, en: 'having the glory of God. Her light was like a most precious stone, as if it were a jasper stone, clear as crystal;', pt: 'tendo a glória de Deus; e o seu brilho era semelhante a uma pedra preciosíssima, como se fosse jaspe cristalino;' },
      { v: 12, en: 'having a great and high wall; having twelve gates, and at the gates twelve angels; and names written on them, which are the names of the twelve tribes of the children of Israel.', pt: 'e tinha um grande e alto muro com doze portas, e nas portas doze anjos, e nomes escritos sobre elas, que são os nomes das doze tribos dos filhos de Israel.' },
      { v: 13, en: 'On the east were three gates; and on the north three gates; and on the south three gates; and on the west three gates.', pt: 'Ao oriente havia três portas, ao norte três portas, ao sul três portas, e ao ocidente três portas.' },
      { v: 14, en: 'The wall of the city had twelve foundations, and on them twelve names of the twelve Apostles of the Lamb.', pt: 'O muro da cidade tinha doze fundamentos, e neles estavam os nomes dos doze apóstolos do Cordeiro.' },
      { v: 15, en: 'He who spoke with me had for a measure a golden reed to measure the city, its gates, and its walls.', pt: 'E aquele que falava comigo tinha por medida uma cana de ouro, para medir a cidade, as suas portas e o seu muro.' },
      { v: 16, en: 'The city is square, and its length is as great as its width. He measured the city with the reed, twelve thousand twelve stadia. Its length, width, and height are equal.', pt: 'A cidade era quadrangular; e o seu comprimento era igual à sua largura. E mediu a cidade com a cana e tinha ela doze mil estádios; e o seu cumprimento, largura e altura eram iguais.' },
      { v: 17, en: 'Its wall is one hundred forty-four cubits, by the measure of a man, that is, of an angel.', pt: 'Também mediu o seu muro, e era de cento e quarenta e quatro côvados, segundo a medida de homem, isto é, de anjo.' },
      { v: 18, en: 'The construction of its wall was jasper. The city was pure gold, like pure glass.', pt: 'O muro era construído de jaspe, e a cidade era de ouro puro, semelhante a vidro límpido.' },
      { v: 19, en: 'The foundations of the city’s wall were adorned with all kinds of precious stones. The first foundation was jasper; the second, sapphire; the third, chalcedony; the fourth, emerald;', pt: 'Os fundamentos do muro da cidade estavam adornados de toda espécie de pedras preciosas. O primeiro fundamento era de jaspe; o segundo, de safira; o terceiro, de calcedônia; o quarto, de esmeralda;' },
      { v: 20, en: 'the fifth, sardonyx; the sixth, sardius; the seventh, chrysolite; the eighth, beryl; the ninth, topaz; the tenth, chrysoprasus; the eleventh, jacinth; and the twelfth, amethyst.', pt: 'o quinto, de sardônica; o sexto, de sárdio; o sétimo, de crisólito; o oitavo, de berilo; o nono, de topázio; o décimo, de crisópraso; o undécimo, de jacinto; o duodécimo, de ametista.' },
      { v: 21, en: 'The twelve gates were twelve pearls. Each one of the gates was made of one pearl. The street of the city was pure gold, like transparent glass.', pt: 'As doze portas eram doze pérolas: cada uma das portas era de uma só pérola; e a praça da cidade era de ouro puro, transparente como vidro.' },
      { v: 22, en: 'I saw no temple in it, for the Lord God, the Almighty, and the Lamb, are its temple.', pt: 'Nela não vi santuário, porque o seu santuário é o Senhor Deus Todo-Poderoso, e o Cordeiro.' },
      { v: 23, en: 'The city has no need for the sun, neither of the moon, to shine, for the very glory of God illuminated it, and its lamp is the Lamb.', pt: 'A cidade não necessita nem do sol, nem da lua, para que nela resplandeçam, porém a glória de Deus a tem alumiado, e o Cordeiro é a sua lâmpada.' },
      { v: 24, en: 'The nations will walk in its light. The kings of the earth bring the glory and honor of the nations into it.', pt: 'As nações andarão à sua luz; e os reis da terra trarão para ela a sua glória.' },
      { v: 25, en: 'Its gates will in no way be shut by day (for there will be no night there),', pt: 'As suas portas não se fecharão de dia, e noite ali não haverá;' },
      { v: 26, en: 'and they shall bring the glory and the honor of the nations into it so that they may enter.', pt: 'e a ela trarão a glória e a honra das nações.' },
      { v: 27, en: 'There will in no way enter into it anything profane, or one who causes an abomination or a lie, but only those who are written in the Lamb’s book of life.', pt: 'E não entrará nela coisa alguma impura, nem o que pratica abominação ou mentira; mas somente os que estão inscritos no livro da vida do Cordeiro.' },
    ],
    22: [
      { v: 1, en: 'He showed me a river of water of life, clear as crystal, proceeding out of the throne of God and of the Lamb,', pt: 'E mostrou-me o rio da água da vida, claro como cristal, que procedia do trono de Deus e do Cordeiro.' },
      { v: 2, en: 'in the middle of its street. On this side of the river and on that was the tree of life, bearing twelve kinds of fruits, yielding its fruit every month. The leaves of the tree were for the healing of the nations.', pt: 'No meio da sua praça, e de ambos os lados do rio, estava a árvore da vida, que produz doze frutos, dando seu fruto de mês em mês; e as folhas da árvore são para a cura das nações.' },
      { v: 3, en: 'There will be no curse any more. The throne of God and of the Lamb will be in it, and his servants will serve him.', pt: 'Ali não haverá jamais maldição. Nela estará o trono de Deus e do Cordeiro, e os seus servos o servirão,' },
      { v: 4, en: 'They will see his face, and his name will be on their foreheads.', pt: 'e verão a sua face; e nas suas frontes estará o seu nome.' },
      { v: 5, en: 'There will be no night, and they need no lamp light; for the Lord God will illuminate them. They will reign forever and ever.', pt: 'E ali não haverá mais noite, e não necessitarão de luz de lâmpada nem de luz do sol, porque o Senhor Deus os alumiará; e reinarão pelos séculos dos séculos.' },
      { v: 6, en: 'He said to me, “These words are faithful and true. The Lord God of the spirits of the prophets sent his angel to show to his bondservants the things which must happen soon.”', pt: 'E disse-me: Estas palavras são fiéis e verdadeiras; e o Senhor, o Deus dos espíritos dos profetas, enviou o seu anjo, para mostrar aos seus servos as coisas que em breve hão de acontecer.' },
      { v: 7, en: '“Behold, I come quickly. Blessed is he who keeps the words of the prophecy of this book.”', pt: 'Eis que cedo venho; bem-aventurado aquele que guarda as palavras da profecia deste livro.' },
      { v: 8, en: 'Now I, John, am the one who heard and saw these things. When I heard and saw, I fell down to worship before the feet of the angel who had shown me these things.', pt: 'Eu, João, sou o que ouvi e vi estas coisas. E quando as ouvi e vi, prostrei-me aos pés do anjo que mas mostrava, para o adorar.' },
      { v: 9, en: 'He said to me, “See you don’t do it! I am a fellow bondservant with you and with your brothers, the prophets, and with those who keep the words of this book. Worship God.”', pt: 'Mas ele me disse: Olha, não faças tal; porque eu sou conservo teu e de teus irmãos, os profetas, e dos que guardam as palavras deste livro. Adora a Deus.' },
      { v: 10, en: 'He said to me, “Don’t seal up the words of the prophecy of this book, for the time is at hand.', pt: 'Disse-me ainda: Não seles as palavras da profecia deste livro; porque próximo está o tempo.' },
      { v: 11, en: 'He who acts unjustly, let him act unjustly still. He who is filthy, let him be filthy still. He who is righteous, let him do righteousness still. He who is holy, let him be holy still.”', pt: 'Quem é injusto, faça injustiça ainda: e quem está sujo, suje-se ainda; e quem é justo, faça justiça ainda; e quem é santo, santifique-se ainda.' },
      { v: 12, en: '“Behold, I come quickly. My reward is with me, to repay to each man according to his work.', pt: 'Eis que cedo venho e está comigo a minha recompensa, para retribuir a cada um segundo a sua obra.' },
      { v: 13, en: 'I am the Alpha and the Omega, the First and the Last, the Beginning and the End.', pt: 'Eu sou o Alfa e o èmega, o primeiro e o derradeiro, o princípio e o fim.' },
      { v: 14, en: 'Blessed are those who do his commandments, that they may have the right to the tree of life, and may enter in by the gates into the city.', pt: 'Bem-aventurados aqueles que lavam as suas vestes [no sangue do Cordeiro] para que tenham direito à arvore da vida, e possam entrar na cidade pelas portas.' },
      { v: 15, en: 'Outside are the dogs, the sorcerers, the sexually immoral, the murderers, the idolaters, and everyone who loves and practices falsehood.', pt: 'Ficarão de fora os cães, os feiticeiros, os adúlteros, os homicidas, os idólatras, e todo o que ama e pratica a mentira.' },
      { v: 16, en: 'I, Jesus, have sent my angel to testify these things to you for the assemblies. I am the root and the offspring of David; the Bright and Morning Star.”', pt: 'Eu, Jesus, enviei o meu anjo para vos testificar estas coisas a favor das igrejas. Eu sou a raiz e a geração de Davi, a resplandecente estrela da manhã.' },
      { v: 17, en: 'The Spirit and the bride say, “Come!” He who hears, let him say, “Come!” He who is thirsty, let him come. He who desires, let him take the water of life freely.', pt: 'E o Espírito e a noiva dizem: Vem. E quem ouve, diga: Vem. E quem tem sede, venha; e quem quiser, receba de graça a água da vida.' },
      { v: 18, en: 'I testify to everyone who hears the words of the prophecy of this book, if anyone adds to them, may God add to him the plagues which are written in this book.', pt: 'Eu testifico a todo aquele que ouvir as palavras da profecia deste livro: Se alguém lhes acrescentar alguma coisa, Deus lhe acrescentará as pragas que estão escritas neste livro;' },
      { v: 19, en: 'If anyone takes away from the words of the book of this prophecy, may God take away his part from the tree of life, and out of the holy city, which are written in this book.', pt: 'e se alguém tirar qualquer coisa das palavras do livro desta profecia, Deus lhe tirará a sua parte da árvore da vida, e da cidade santa, que estão descritas neste livro.' },
      { v: 20, en: 'He who testifies these things says, “Yes, I come quickly.” Amen! Yes, come, Lord Jesus.', pt: 'Aquele que testifica estas coisas diz: Certamente cedo venho. Amém; vem, Senhor Jesus.' },
      { v: 21, en: 'The grace of the Lord Jesus Christ be with all the saints. Amen.', pt: 'A graça do Senhor Jesus seja com todos.' },
    ],
  },
};

export default book;
